var User = mongoose.model("User", new mongoose.Schema({
  name:{type:String,required:true}, username:{type:String,required:true,unique:true},
  password:{type:String,required:true}, email:{type:String,default:""}, phone:{type:String,default:""},
  role:{type:String,enum:["admin","sales_admin","hr","director","manager","team_leader","sales","viewer"],default:"sales"},
  title:{type:String,default:""}, active:{type:Boolean,default:true},
  monthlyTarget:{type:Number,default:15}, teamId:{type:String,default:""}, teamName:{type:String,default:""}, lastSeen:{type:Date,default:null}, lastActive:{type:Date,default:null}, qTargets:{type:Object,default:{}}, reportsTo:{type:mongoose.Schema.Types.ObjectId,ref:"User",default:null},
  startingDate:{type:Date,default:null},
  // Attendance & Salary system (docs/attendance-salary-requirements.md §17).
  // baseSalary in EGP, null for Owner (admin) — excluded from all salary lists.
  // saturdayPatternStartDate is required when saturdaySchedule="alternating".
  baseSalary:{type:Number,default:null},
  saturdaySchedule:{type:String,enum:["always_work","always_off","alternating"],default:"always_work"},
  saturdayPatternStartDate:{type:Date,default:null},
  // Owner-only forgot-password flow. isOwner gates eligibility; the actual
  // owner is amgadm22@gmail.com (see scripts/set-owner-flag.js). resetToken
  // is a 64-hex single-use string with 1h expiry. passwordChangedAt is set
  // on every successful reset and checked by auth() against decoded.iat to
  // force-logout pre-reset JWTs (mirrors the active-toggle force-logout).
  isOwner:{type:Boolean,default:false},
  resetToken:{type:String,default:null,index:true},
  resetTokenExpiry:{type:Date,default:null},
  passwordChangedAt:{type:Date,default:null},
  // Per-agent daily lead cap for auto-rotation. null = unlimited (no cap).
  // 0 = effectively paused (every rotation skips this agent). Positive int
  // = max number of leads they can receive via auto-rotation in a single
  // calendar day (server time / Africa/Cairo). Counted from agentHistory[]
  // Rotation entries where date >= start of today. Manual /rotate ignores
  // this cap entirely (admin override).
  dailyLeadCap:{type:Number,default:null,min:0},
  // Capacitor Push Notifications registry. One entry per (device,platform)
  // registration. token = FCM/APNs token from Capacitor's PushNotifications
  // plugin. Deduped by token value in POST /api/users/push-token. Invalid
  // tokens are pruned lazily by notifications.js when FCM returns
  // 'registration-token-not-registered' / 'invalid-registration-token'.
  pushTokens:[{token:String,platform:String,deviceId:String,addedAt:{type:Date,default:Date.now}}]
},{timestamps:true}));

var Lead = mongoose.model("Lead", new mongoose.Schema({
  name:{type:String,required:true}, phone:{type:String,required:true}, phone2:{type:String,default:""},
  email:{type:String,default:""}, status:{type:String,default:"NewLead"},
  // Phase A2 (2026-05-05): default removed. Was "Facebook" — silent fallback
  // that masked the source-data quality issue (98.3% of leads tagged Facebook
  // because the Google Apps Script intake didn't send a source field). Apps
  // Script + Sheet now send source explicitly, and POST /api/leads validates
  // non-empty source server-side — see server.js:2337 area.
  source:{type:String,default:""}, project:{type:String,default:""}, unitType:{type:String,default:""}, campaign:{type:String,default:""},
  // Inbound webhook fields — populated by POST /api/leads/inbound when leads
  // arrive from facebook/instagram/tiktok/snapchat/whatsapp. externalId is the
  // platform's lead id (used together with source for dedupe).
  externalId:{type:String,default:""}, formId:{type:String,default:""},
  adName:{type:String,default:""}, adsetName:{type:String,default:""},
  agentId:{type:mongoose.Schema.Types.ObjectId,ref:"User"}, budget:{type:String,default:""},
  notes:{type:String,default:""}, callbackTime:{type:String,default:""},
  lastActivityTime:{type:Date,default:Date.now}, archived:{type:Boolean,default:false}, isVIP:{type:Boolean,default:false},
  eoiDeposit:{type:String,default:""}, eoiDate:{type:String,default:""},
  eoiApproved:{type:Boolean,default:false}, eoiImage:{type:String,default:""},
  eoiDocuments:[{type:mongoose.Schema.Types.Mixed}],
  preEoiStatus:{type:String,default:""},
  eoiStatus:{type:String,default:""}, // "" | "Pending" | "Approved" | "EOI Cancelled"
  preDealStatus:{type:String,default:""},
  dealStatus:{type:String,default:""}, // "" | "Deal Cancelled"
  stages:{type:mongoose.Schema.Types.Mixed,default:{}},
  dealApproved:{type:Boolean,default:false}, dealImages:[{type:String}],
  commissionClaimDate:{type:String,default:""}, commissionClaimed:{type:Boolean,default:false},
  splitAgent2Id:{type:mongoose.Schema.Types.ObjectId,ref:"User",default:null},
  splitAgent2Name:{type:String,default:""},
  projectWeight:{type:Number,default:1},
  dealDate:{type:String,default:""},
  lastRotationAt:{type:Date,default:null}, rotationCount:{type:Number,default:0},
  // Rotation kill-switch — flipped true after 3 consecutive agents mark the
  // lead "Not Interested" (tracked by notInterestedStreak). Once true, every
  // rotation endpoint bails out; admin can reset it by editing the lead.
  rotationStopped:{type:Boolean,default:false},
  notInterestedStreak:{type:Number,default:0},
  locked:{type:Boolean,default:false},
  // Phase R-13.3 — lock audit metadata. Stamped when lock toggles
  // false→true via PUT /api/leads/:id; cleared on the reverse transition.
  // Read by the Rotation Diagnostics page's Locked Leads section. Locks
  // applied before this commit have null/empty values (the diagnostics UI
  // shows "—" in that case).
  lockedAt:{type:Date,default:null},
  lockedBy:{type:String,default:""},
  lastFeedback:{type:String,default:""},
  // Permanent meeting marker — once set, must never be cleared or overwritten.
  // hadMeeting records that the lead has reached MeetingDone at least once,
  // meetingDoneAt is the first time it happened so period-based reports can
  // still bucket it correctly even after the status moves on.
  hadMeeting:{type:Boolean,default:false},
  meetingDoneAt:{type:Date,default:null},
  // Full audit timeline (admin-only view). Every create / assign / rotate /
  // status change / feedback / callback pushes a single {event, description,
  // byUser, toAgent, timestamp} entry. Append-only — never cleared.
  history:{type:[mongoose.Schema.Types.Mixed],default:[]},
  agentHistory:{type:[mongoose.Schema.Types.Mixed],default:[]},
  assignments:[{
    agentId:{type:mongoose.Schema.Types.ObjectId,ref:"User"},
    status:{type:String,default:"NewLead"},
    notes:{type:String,default:""},
    budget:{type:String,default:""},
    callbackTime:{type:String,default:""},
    lastFeedback:{type:String,default:""},
    lastActionAt:{type:Date,default:Date.now},
    rotationTimer:{type:Date,default:Date.now},
    // Set ONLY when slice.status transitions to a different value. Used by
    // the CallBack rotation rule to measure cbHours from the moment the
    // agent (or admin) flipped this slice into CallBack — NOT from the
    // user-typed callbackTime, NOT bumped by notes/budget edits. Legacy
    // slices without this field fall back to lastActionAt / assignedAt /
    // lead.createdAt at eligibility-evaluator read time.
    statusChangedAt:{type:Date,default:null},
    noRotation:{type:Boolean,default:false},
    nextCallAt:{type:Date,default:null},
    assignedAt:{type:Date,default:Date.now},
    agentHistory:{type:[mongoose.Schema.Types.Mixed],default:[]},
    // Sibling rule to the Phase P 7-day staleness check. Set true by the
    // admin-triggered POST /api/agents/:id/unassign-all-leads endpoint to
    // produce the same hide-effect immediately. Read-time only — checked
    // alongside isAssignmentStale in the same call sites; bypassed by
    // isEoiOrDoneDeal exactly like the 7-day rule. Sticky: cleared only by
    // a fresh $push of the slice (rotation), never auto-cleared.
    hiddenManually:{type:Boolean,default:false},
    // Author of the slice's CURRENT notes/lastFeedback. Set by the feedback
    // endpoint when a manager writes to this slice; cleared (set to the slice's
    // own agent) when the agent themselves writes via PUT. Empty strings/null
    // when the agent wrote (legacy + sales path) — UI uses this to render a
    // "from <Manager>" tag for the agent.
    notesAuthorId:{type:mongoose.Schema.Types.ObjectId,ref:"User",default:null},
    notesAuthorName:{type:String,default:""},
    notesAuthorRole:{type:String,default:""},
    // Soft-remove marker. null = slice is active (currently assigned).
    // Non-null Date = admin removed this agent from the lead; slice is
    // preserved with all its feedback/notes/agentHistory but is excluded from
    // every "current/active" read path (sales list/detail, feedback target,
    // dup-check, scope gates) and from auto-rotation eligibility consideration.
    // The agent stays in lead.previousAgentIds so auto-rotation will never
    // re-route the lead to them automatically — the dedicated reactivation
    // branch in POST /api/leads/:id/rotate is the only way back. Reactivation
    // clears removedAt and refreshes assignedAt / lastActionAt / rotationTimer
    // / statusChangedAt; notes / lastFeedback / agentHistory are preserved.
    removedAt:{type:Date,default:null}
  }],
  // Author-scoped private notes. Each entry visible to its author only —
  // server filters at read time on every endpoint that returns the lead.
  // Append-only; managers cannot delete other managers' entries.
  privateNotes:[{
    authorId:{type:mongoose.Schema.Types.ObjectId,ref:"User",required:true},
    authorName:{type:String,default:""},
    authorRole:{type:String,default:""},
    text:{type:String,required:true},
    createdAt:{type:Date,default:Date.now}
  }],
  previousAgentIds:[{type:mongoose.Schema.Types.ObjectId,ref:"User"}],
  globalStatus:{type:String,default:"active"},
  expiresAt:{type:Date,default:null},
  // Manual Assignment Window: when settings.manualAssignmentWindowMinutes > 0
  // and a new lead is created without an agent, the lead goes into an
  // "unassigned queue" for admins to manually assign. After this timestamp
  // passes, the background sweeper auto-rotates it to Tier 1.
  manualWindowExpiresAt:{type:Date,default:null,index:true},
  // Phase R-12 Part 2 — External-deal fields. All optional; default values
  // mean every existing lead reads as a normal internal deal (no migration
  // needed). Only consulted by Phase R-12 Parts 3-6 (Add/Edit Deal modal,
  // Deals/Claims filter pills, Commission.externalSplit computation).
  // - dealType "internal": externalBrokerId + externalDealConfig are
  //   ignored. Existing recipient logic runs unchanged.
  // - dealType "external": externalBrokerId required + both pcts > 0
  //   (enforced at the Lead PUT site that flips dealType in Part 3,
  //   NOT at schema level — leaving them write-time validations keeps
  //   existing PUTs that never touch dealType from accidentally tripping).
  // Broker model is declared further down (~line 540); the "Broker" ref
  // string is resolved at populate-time, not schema-define-time, so the
  // forward reference is fine.
  dealType:{type:String,enum:["internal","external"],default:"internal"},
  externalBrokerId:{type:mongoose.Schema.Types.ObjectId,ref:"Broker",default:null},
  externalDealConfig:{
    commissionTaxPct:{type:Number,default:0},
    brokerSharePct:{type:Number,default:0}
  },
  // Commission claim from the developer for this deal.
  // commissionRate: percent value typed in the deal form (e.g. 3 for 3%).
  // commissionAmount: always computed server-side as round2(budget × rate / 100);
  // never trusted from the client. Separate from `budget` (deal value).
  // Both required on admin's DoneDeal save path; null on pre-existing deals.
  commissionRate:{type:Number,default:null},
  commissionAmount:{type:Number,default:null},
  // External-deal optional "Sales Agent involved" toggle. When enabled, a
  // second sales agent (not in the Lead's reportsTo chain) is paid a manual
  // EGP amount on this deal. The per-1000 chain (TL/manager/director/owner)
  // is NEVER paid for External deals regardless of this toggle — only the
  // broker (always) and this external sales agent (when enabled).
  externalSalesAgentEnabled:{type:Boolean,default:false},
  externalSalesAgentId:{type:mongoose.Schema.Types.ObjectId,ref:"User",default:null},
  externalSalesAgentName:{type:String,default:""},
  externalSalesAgentManualAmount:{type:Number,default:null},
  // Phase R-13.2 — who funds the external sales agent's manual amount.
  // "company" (default): company pays sales out of its net; broker's owed
  //   is the original gross. Today's behavior.
  // "broker": broker pays sales out of their share; commission.externalSplit
  //   .brokerNetOwed downgrades to brokerOwed − manualAmount, and the
  //   sales agent recipient still reads as owed manualAmount.
  // Forced to "company" whenever externalSalesAgentEnabled is false.
  externalSalesAgentPaidBy:{type:String,enum:["company","broker"],default:"company"},
  // Callback-reminder dedupe: timestamp of the last "callback due in 2 min"
  // push for the lead's CURRENT callbackTime. sweepDueCallbacks fires only
  // when this is null OR older than callbackTime, so rescheduling re-arms it.
  callbackNotifiedAt:{type:Date,default:null}
},{timestamps:true}));

// Indexes for query performance
Lead.collection.createIndex({ "assignments.agentId": 1 }).catch(function(){});
Lead.collection.createIndex({ agentId: 1 }).catch(function(){});
Lead.collection.createIndex({ createdAt: -1 }).catch(function(){});
Lead.collection.createIndex({ globalStatus: 1 }).catch(function(){});
Lead.collection.createIndex({ archived: 1, agentId: 1 }).catch(function(){});
Lead.collection.createIndex({ "assignments.agentId": 1, createdAt: -1 }).catch(function(){});

// Reports — Phase 1: speed up KPI / Funnel / Source-ROI aggregations.
// status+createdAt covers period-bounded "deals in range" and "leads in range" queries.
// source+status covers source-filtered status counts driving Source ROI.
Lead.collection.createIndex({ status: 1, createdAt: -1 }).catch(function(){});
Lead.collection.createIndex({ source: 1, status: 1 }).catch(function(){});

// Archive page support — pairs with the {archived:1, agentId:1} index above
// to cover both per-agent and sort-newest-first queries on archived rows.
// Non-unique; safe to add hot.
Lead.collection.createIndex({ archived: 1, createdAt: -1 }).catch(function(){});

// Inbound dedupe — sparse so manually-created leads (no externalId) don't share
// the index. Compound (externalId, source) matches the inbound dedupe query and
// allows the same external id across different platforms.
Lead.collection.createIndex(
  { externalId: 1, source: 1 },
  { sparse: true, partialFilterExpression: { externalId: { $type: "string", $gt: "" } }, name: "inbound_externalId_source" }
).catch(function(e){
  console.error("[externalId index] not created:", e && e.message ? e.message : e);
});

// Phase II indexes — User.reportsTo + Lead.splitAgent2Id (Activity + DailyRequest
// indexes registered further down once those models are declared).
User.collection.createIndex({ reportsTo: 1 }).catch(function(){});
Lead.collection.createIndex({ splitAgent2Id: 1 }).catch(function(){});
Lead.collection.createIndex({ splitAgent2Id: 1, createdAt: -1 }).catch(function(){});

// Rotation sweep — sweepAutoRotation sorts up-to-1000 candidates by
// lastRotationAt asc; without a covering index the in-memory sort blew the
// 32MB limit once the assigned-lead pool grew past ~1k and every tick was
// exiting with "Sort exceeded memory limit". Partial filter only includes
// the two predicates the planner can prove are implied by the sweep query
// (archived: false equality, agentId: $ne null implies $exists: true);
// locked/rotationStopped use $ne in the query and aren't planner-implied by
// equality, so they get post-scan-filtered from the already-narrowed set.
Lead.collection.createIndex(
  { lastRotationAt: 1 },
  {
    partialFilterExpression: { archived: false, agentId: { $exists: true } },
    name: "lastRotationAt_active_assigned"
  }
).catch(function(e){
  console.error("[lastRotationAt index] not created:", e && e.message ? e.message : e);
});

// STEP 4-2 — callback migration indexes. callbackTime is a String (ISO 8601)
// so range queries against ISO strings sort lexicographically. Partial filter
// keeps the index small (only ~64% of leads have a non-empty callbackTime).
// agentId+callbackTime covers the sales-role scope on the new
// /api/leads/callbacks endpoint; the bare callbackTime index covers admin/SA.
// assignments.agentId+assignments.callbackTime covers the per-current-assignment
// scan in /api/reports/callback-compliance.
Lead.collection.createIndex(
  { callbackTime: 1 },
  { partialFilterExpression: { callbackTime: { $type: "string", $gt: "" } }, name: "callbackTime_partial" }
).catch(function(){});
Lead.collection.createIndex(
  { agentId: 1, callbackTime: 1 },
  { partialFilterExpression: { callbackTime: { $type: "string", $gt: "" } }, name: "agentId_callbackTime_partial" }
).catch(function(){});
Lead.collection.createIndex({ "assignments.agentId": 1, "assignments.callbackTime": 1 }).catch(function(){});

// Meeting aggregation indexes — sales-ranking meetRows matches
// { hadMeeting: true, agentId: { $in: salesIds } } and my-stats meetLeads
// matches { agentId, $or: [{ hadMeeting: true }, { status: "MeetingDone" }] }
// then range-filters on $ifNull($meetingDoneAt, $updatedAt). Without an index
// covering hadMeeting + agentId the meetRows scan fell back to { agentId: 1 }
// then per-doc hadMeeting filter, which is the slowest of the 4 parallel
// aggregations in /api/dashboard/sales-ranking.
Lead.collection.createIndex({ hadMeeting: 1, agentId: 1 }).catch(function(){});
Lead.collection.createIndex({ agentId: 1, meetingDoneAt: 1 }).catch(function(){});

// Safety-net unique index on phone. Partial filter skips empty strings so the
// constraint only applies to rows with a real phone value. If pre-existing
// duplicates cause creation to fail, log and continue — the app-level guard in
// POST /api/leads / FB webhook still blocks new duplicates.
Lead.collection.createIndex(
  { phone: 1 },
  { unique: true, partialFilterExpression: { phone: { $type: "string", $gt: "" } }, name: "uniq_phone" }
).catch(function(e){
  console.error("[phone unique index] not created:", e && e.message ? e.message : e);
});

var Activity = mongoose.model("Activity", new mongoose.Schema({
  userId:{type:mongoose.Schema.Types.ObjectId,ref:"User",required:true},
  leadId:{type:mongoose.Schema.Types.ObjectId,ref:"Lead"},
  type:{type:String,default:"call"}, note:{type:String,default:""},
  // Client snapshot at the time of the action — captured by POST /api/activities
  // so the dashboard never has to cross-join Lead/DailyRequest at render time.
  // populate("leadId") only resolves Lead docs; DR-backed activities lose the
  // populated name, which is what made the "Note added" rows render "no client".
  clientName:{type:String,default:""}, clientPhone:{type:String,default:""}
},{timestamps:true}));

var Notification = mongoose.model("Notification", new mongoose.Schema({
  type:{type:String,required:true}, // "deal" or "rotation"
  leadName:{type:String,default:""},
  leadId:{type:String,default:""},
  agentName:{type:String,default:""},
  fromName:{type:String,default:""},
  toName:{type:String,default:""},
  status:{type:String,default:""},
  budget:{type:String,default:""},
  reason:{type:String,default:""},
  // 2026-05-18 — event time stored separately from createdAt. createdAt is
  // when the Notification row was INSERTED (which for backfilled rows is
  // ~identical across all of them, so every notification rendered as
  // "1 day ago"); eventTime is when the underlying event actually happened
  // (Lead.dealDate for DoneDeal, Lead.eoiDate for EOI, lead.lastRotationAt
  // for rotation). FE renders timeAgo(n.eventTime || n.createdAt).
  eventTime:{type:Date,default:null},
  seenBy:[{type:String}]
},{timestamps:true}));

// Notification indexes — added 2026-05-10 after a live audit found the
// collection was running every query as a full _id-only scan over 8,684 rows.
// Hottest patterns: getVisibleNotifications (.find({type:...}).sort({createdAt:-1})),
// the cascade Notification.deleteMany({leadId}) in the lead/DR delete+archive
// paths, and the off-site dedupe lookup .findOne({type:"offsite_pending", fromName}).
// Errors on creation are warned but not rethrown so a single bad index doesn't
// take the process down — visible in logs if it ever fails to build.
Notification.collection.createIndex({ type: 1, createdAt: -1 }).catch(function(e){
  console.error("[notification index type+createdAt] not created:", e && e.message ? e.message : e);
});
Notification.collection.createIndex({ leadId: 1 }).catch(function(e){
  console.error("[notification index leadId] not created:", e && e.message ? e.message : e);
});
Notification.collection.createIndex({ fromName: 1 }).catch(function(e){
  console.error("[notification index fromName] not created:", e && e.message ? e.message : e);
});

// AppSetting — key/value store for global CRM settings (rotation config etc).
// Single source of truth across all clients and server-side jobs.
var AppSetting = mongoose.model("AppSetting", new mongoose.Schema({
  key:{type:String,required:true,unique:true},
  value:{type:mongoose.Schema.Types.Mixed,default:{}}
},{timestamps:true}));

// SettingsAudit — one row per changed field on a settings save. Powers the
// Settings → Audit Log tab and the rollback endpoint.
var settingsAuditSchema = new mongoose.Schema({
  timestamp:  { type: Date, default: Date.now, index: -1 },
  actorId:    { type: mongoose.Schema.Types.ObjectId, ref: "User" },
  actorName:  { type: String, default: "" },
  field:      { type: String, required: true },
  oldValue:   { type: mongoose.Schema.Types.Mixed },
  newValue:   { type: mongoose.Schema.Types.Mixed },
  rolledBack: { type: Boolean, default: false }
}, { timestamps: true });
var SettingsAudit = mongoose.model("SettingsAudit", settingsAuditSchema);

// AgentVacation — per-agent date ranges where the agent is excluded from
// auto-rotation. Admin / Sales Admin write; rotation picker reads via
// isOnVacation() (30s cached) + a per-sweep bulk prefetch.
var agentVacationSchema = new mongoose.Schema({
  agentId:   { type: mongoose.Schema.Types.ObjectId, ref: "User", required: true },
  startDate: { type: Date, required: true },
  endDate:   { type: Date, required: true },
  reason:    { type: String, default: "" },
  createdBy: { type: mongoose.Schema.Types.ObjectId, ref: "User" },
  createdAt: { type: Date, default: Date.now }
});
agentVacationSchema.index({ agentId: 1, endDate: 1 });
var AgentVacation = mongoose.model("AgentVacation", agentVacationSchema);

// =====================================================================
// COMMISSION SYSTEM — Phase A foundation
// One Commission per closed Lead (Lead.status === "DoneDeal"). Snapshot
// fields are hard copies — they survive User deactivation/deletion. Cycles
// + incentives embedded; bounded count per deal, always read together.
// =====================================================================

// Recipient appears inside snapshot.salesAgent / teamLeader / manager /
// director / splitChain.*. userName is authoritative; userId is convenience-only
// and may dangle.
//
// Phase R-1: replaces per-recipient distributionType/value with per-1000
// computed shares. computedShare is the authoritative number owed to this
// recipient (before override). overrideAmount, if set (>0), wins over computedShare
// when calculating effective owed for payout / debt math. Recompute updates the
// computed fields but never touches overrides — admin must clear them explicitly.
var commissionRecipientSchema = new mongoose.Schema({
  userName:          { type: String, required: true },
  userId:            { type: mongoose.Schema.Types.ObjectId, ref: "User", default: null },
  userActiveAtClose: { type: Boolean, default: true },
  role:              { type: String, enum: ["sales","team_leader","manager","director"], required: true },

  // Computed at snapshot creation/recompute time (Phase R-1).
  computedShare:        { type: Number, default: 0 },     // EGP owed (before override)
  rate:                 { type: Number, default: 0 },     // per-1000 rate used (5/6/7/2/1/0.5)
  rateBucket:           { type: String, default: "" },    // "base" | "target_met" | "double_target" | "fixed"
  isHalfWeight:         { type: Boolean, default: false }, // projectWeight < 1
  effectiveDealTotal:   { type: Number, default: 0 },     // dealTotal × projectWeight × splitMultiplier
  targetSnapshot:       { type: Number, default: 0 },     // sales agent's Q target at compute time
  performanceSnapshot:  { type: Number, default: 0 },     // sales agent's Q effective achievement at compute time

  // Override — admin sets explicitly, recompute leaves untouched.
  overrideAmount:       { type: Number, default: null },
  overrideReason:       { type: String, default: "" },

  computedAt:           { type: Date, default: null }
}, { _id: false });

// Single stage marker inside a cycle. Empty date => stage not reached yet.
var commissionStageSchema = new mongoose.Schema({
  date:   { type: String, default: "" },     // ISO yyyy-mm-dd entered by admin
  notes:  { type: String, default: "" },
  byUser: { type: String, default: "" }      // SNAPSHOT of admin name who marked
}, { _id: false });

// Cycle records cash flow from the developer only. Per-recipient payouts moved
// to Commission.payouts[] in Phase R-1 (cycle.payoutBreakdown dropped).
// Phase R-5 added claimUnitValue + commissionRate + claimAmount for tax tracking.
// claimAmount is the GROSS invoice value billed to the developer (incl. 14% VAT).
// receivedAmount stays as admin-entered net cash actually received (unchanged
// semantic). Old cycles created before R-5 have all three new fields = 0; they
// are excluded from the annual summary, never backfilled.
var commissionCycleSchema = new mongoose.Schema({
  cycleNumber:        { type: Number, required: true },
  state:              { type: String,
                        enum: ["pending_claim","claim_submitted","invoice_submitted","received","paid_to_team","cancelled"],
                        default: "pending_claim" },
  expectedAmount:     { type: Number, default: 0 },
  // Phase R-5 — tax tracking inputs.
  claimUnitValue:     { type: Number, default: 0 },   // قيمه الوحده (per-unit price billed)
  commissionRate:     { type: Number, default: 0 },   // نسبه العموله (0.03 = 3%)
  claimAmount:        { type: Number, default: 0 },   // = claimUnitValue × commissionRate (gross invoice incl. VAT)
  receivedAmount:     { type: Number, default: 0 },   // admin-entered net cash actually received
  claim_submitted:    { type: commissionStageSchema, default: function(){ return {}; } },
  invoice_submitted:  { type: commissionStageSchema, default: function(){ return {}; } },
  received:           { type: commissionStageSchema, default: function(){ return {}; } },
  paid_to_team:       { type: commissionStageSchema, default: function(){ return {}; } },
  closedAt: { type: Date, default: null }
}, { _id: true, timestamps: true });

// Per-payout event — money flowing from us to a recipient. Created by
// POST /api/commissions/:id/payouts. appliedToDebt is auto-computed at
// creation time from the recipient's current net position across all
// commissions; netPaid = amount - appliedToDebt.
var commissionPayoutSchema = new mongoose.Schema({
  recipientUserName: { type: String, required: true },
  recipientUserId:   { type: mongoose.Schema.Types.ObjectId, ref: "User", default: null },
  recipientRole:     { type: String, enum: ["sales","team_leader","manager","director"], required: true },
  amount:            { type: Number, required: true },     // requested amount (before debt deduction)
  appliedToDebt:     { type: Number, default: 0 },         // deducted to satisfy prior overpayment
  netPaid:           { type: Number, default: 0 },         // amount - appliedToDebt (what recipient actually got)
  date:              { type: String, default: "" },        // ISO yyyy-mm-dd
  notes:             { type: String, default: "" },
  byUser:            { type: String, default: "" }
}, { _id: true, timestamps: true });

var commissionIncentiveSchema = new mongoose.Schema({
  recipients: [{
    userName:     { type: String, required: true },
    userId:       { type: mongoose.Schema.Types.ObjectId, ref: "User", default: null },
    role:         { type: String, enum: ["sales","team_leader","manager","director"], required: true },
    amount:       { type: Number, default: 0 },
    status:       { type: String, enum: ["pending","received"], default: "pending" },
    receivedDate: { type: String, default: "" }
  }]
}, { _id: false });

// Phase R-12 Part 5 — externalSplit subdoc is defined inline on
// commissionSchema below (with brokerPayouts as an inline subarray). Reference:
// math is documented at the externalSplit field site (commissionSchema:526).
//   gross 100,000, tax 30%, broker 80%  → broker 56,000 EGP / ARO 14,000 EGP
// computeAllRecipientShares is the single writer of the four computed amounts.

var commissionSchema = new mongoose.Schema({
  leadId:              { type: mongoose.Schema.Types.ObjectId, ref: "Lead", required: true, index: true },

  // Snapshot — never overwritten on Lead changes; only via explicit admin edit.
  snapshot: {
    customerName:    { type: String, required: true },
    customerPhone:   { type: String, default: "" },
    developer:       { type: String, default: "" },     // free text, admin fills
    unitDetails:     { type: String, default: "" },     // free text, admin fills
    projectName:     { type: String, default: "" },
    dealTotal:       { type: Number, default: 0 },      // EGP (parsed Lead.budget)
    dealDate:        { type: String, default: "" },     // ISO from Lead.dealDate
    // Phase R-12 — broker-only external deals have NO internal sales agent
    // (externalSalesAgentEnabled=false AND Lead.agentId=null). buildSnapshotForLead
    // returns salesAgent:null for that shape, so this MUST default to null rather
    // than required:true — otherwise Commission.create throws a ValidationError
    // and the deal silently gets no commission.
    salesAgent:      { type: commissionRecipientSchema, default: null },
    teamLeader:      { type: commissionRecipientSchema, default: null },
    manager:         { type: commissionRecipientSchema, default: null },
    director:        { type: commissionRecipientSchema, default: null },
    isSplitDeal:     { type: Boolean, default: false },
    splitChain: {
      salesAgent2:   { type: commissionRecipientSchema, default: null },
      teamLeader2:   { type: commissionRecipientSchema, default: null },
      manager2:      { type: commissionRecipientSchema, default: null },
      director2:     { type: commissionRecipientSchema, default: null }
    }
  },

  expectedTotal:           { type: Number, default: 0 },
  expectedCollectionDate:  { type: String, default: "" },

  status:        { type: String, enum: ["active","cancelled","fully_paid"], default: "active", index: true },
  cancelledAt:   { type: Date, default: null },
  cancelReason:  { type: String, default: "" },

  cycles:        [commissionCycleSchema],
  payouts:       [commissionPayoutSchema],
  incentive:     { type: commissionIncentiveSchema, default: function(){ return { recipients: [] }; } },

  // Phase R-12 Part 5 — external-deal split. isExternal is the master flag;
  // when false, every other field is ignored and the commission behaves
  // exactly as today. brokerName is a SNAPSHOT taken at commission-creation
  // time (matches how snapshot.salesAgent.userName freezes — a Broker rename
  // later does not retroactively rewrite past commissions). The four computed
  // fields (commissionTaxAmount/aroNetAmount/brokerOwed/aroOwed) are populated
  // by computeAllRecipientShares from the running gross commission claim
  // (Σ cycle.claimAmount). brokerPayouts is a separate subdoc array — kept
  // OUT of payouts[] so the existing recipientRole enum + aggregations
  // (computeRecipientNetPositions, payout report) remain unchanged. Internal
  // team payouts on external deals still go in the regular payouts[] array.
  externalSplit: {
    isExternal:          { type: Boolean, default: false },
    brokerId:            { type: mongoose.Schema.Types.ObjectId, ref: "Broker", default: null },
    brokerName:          { type: String, default: "" },
    commissionTaxPct:    { type: Number, default: 0 },
    brokerSharePct:      { type: Number, default: 0 },
    // Computed by computeAllRecipientShares — round2-rounded:
    commissionTaxAmount: { type: Number, default: 0 },
    aroNetAmount:        { type: Number, default: 0 },
    brokerOwed:          { type: Number, default: 0 },
    // Phase R-13.2 — broker's effective take-home after the optional sales
    // agent deduction. Equals brokerOwed when salesAgentPaidBy==="company"
    // (default) OR when the sales agent toggle is OFF. When paidBy==="broker",
    // brokerNetOwed = max(0, brokerOwed - externalSalesAgentManualAmount).
    // All payout/cash-flow/recipient reads should prefer this when present.
    brokerNetOwed:       { type: Number, default: 0 },
    aroOwed:             { type: Number, default: 0 },
    // Phase R-13.2 — snapshot of Lead.externalSalesAgentPaidBy at compute
    // time. Drives the brokerNetOwed math above and the Broker Calc modal's
    // screen/print branches.
    salesAgentPaidBy:    { type: String, enum: ["company", "broker"], default: "company" },
    // Broker payment tracking (parallel to commission.payouts[] for internal
    // recipients). Append-only; brokerPaid (the running sum of amount) and
    // brokerRemaining (brokerOwed - brokerPaid) are derived at read time.
    brokerPayouts: [{
      amount: { type: Number, required: true },
      date:   { type: String, default: "" },     // ISO yyyy-mm-dd
      notes:  { type: String, default: "" },
      byUser: { type: String, default: "" }      // SNAPSHOT of admin name
    }]
  },

  // Phase R-1: snapshot of the per-1000 rates active at compute time, so the
  // commission stays interpretable even after Settings rates change.
  ratesSnapshot: {
    sales: {
      base:          { type: Number, default: 5 },
      target_met:    { type: Number, default: 6 },
      double_target: { type: Number, default: 7 }
    },
    team_leader:     { type: Number, default: 2 },
    manager:         { type: Number, default: 1 },
    director:        { type: Number, default: 0.5 }
  },
  computedAt:    { type: Date, default: null },

  // Per-deal admin recipient overrides (Phase R-13). Three actions:
  //   manual_add    — add an extra recipient (chain or off-chain) with a manual amount.
  //                   targetSlot is "extra"; userId is optional (null for non-User names).
  //   manual_zero   — pin a chain slot's effective share to 0 without removing it.
  //                   targetSlot is one of the snapshot slot keys (e.g. "teamLeader").
  //   manual_remove — exclude a chain slot from the effective recipient list entirely.
  //                   targetSlot is the slot key; computedShare ignored.
  // Computed shares on commission.snapshot.* are NOT mutated. The effective
  // recipient list is derived at read time by combining snapshot + overrides.
  recipientOverrides: [{
    targetSlot:    { type: String, required: true },  // "salesAgent" | "teamLeader" | "manager" | "director" | "salesAgent2" | "teamLeader2" | "manager2" | "director2" | "extra"
    source:        { type: String, enum: ["manual_add","manual_zero","manual_remove"], required: true },
    userId:        { type: mongoose.Schema.Types.ObjectId, ref: "User", default: null },
    name:          { type: String, default: "" },
    role:          { type: String, enum: ["sales","team_leader","manager","director"], default: "sales" },
    computedShare: { type: Number, default: 0 },
    addedBy:       { type: String, default: "" },     // admin name SNAPSHOT
    addedAt:       { type: Date, default: Date.now }
  }],

  lastAlertedAt: { type: Date, default: null }
}, { timestamps: true });

commissionSchema.index({ leadId: 1, status: 1 });
commissionSchema.index({ status: 1, expectedCollectionDate: 1 });
commissionSchema.index({ createdAt: -1 });

var Commission = mongoose.model("Commission", commissionSchema);

// Phase R-13.3 — RotationRunLog: persistent record of each sweepAutoRotation
// tick. Powers the Rotation Diagnostics page (GET /api/rotation/diagnostics).
// Pruned to the last 30 runs at end of each sweep — older entries dropped.
// rotatedLeads + skippedLeads are capped at 200 entries each to bound doc
// size on long candidate lists. skippedReasons aggregates ALL skips (not
// capped) so the histogram is accurate even when the detail list is truncated.
var RotationRunLog = mongoose.model("RotationRunLog", new mongoose.Schema({
  startedAt:      { type: Date, required: true, index: true },
  finishedAt:     { type: Date, default: null },
  evaluated:      { type: Number, default: 0 },
  rotated:        { type: Number, default: 0 },
  skipped:        { type: Number, default: 0 },
  skippedReasons: { type: Object, default: {} },   // { "<reason text>": count }
  rotatedLeads:   [{
    leadId:    { type: mongoose.Schema.Types.ObjectId, ref: "Lead" },
    leadName:  String,
    fromAgent: String,
    toAgent:   String,
    firedRule: String
  }],
  skippedLeads:   [{
    leadId:       { type: mongoose.Schema.Types.ObjectId, ref: "Lead" },
    leadName:     String,
    currentAgent: String,
    status:       String,
    lastActionAt: Date,
    callbackTime: Date,
    reason:       String
  }]
}, { timestamps: true }));

// Phase R-5 — VAT payment tracking. One row per month-of-claim, marking the
// month's accumulated VAT as paid to the tax authority. month is "YYYY-MM"
// matching the CLAIM month (not the payment month). Unique by month, upserted
// on POST /api/vat-payments, removed by DELETE /api/vat-payments/:month.
var vatPaymentSchema = new mongoose.Schema({
  month:           { type: String, required: true, unique: true }, // "YYYY-MM"
  paidAt:          { type: Date, default: Date.now },
  markedByUserId:  { type: mongoose.Schema.Types.ObjectId, ref: "User", default: null }
}, { timestamps: true });
var VatPayment = mongoose.model("VatPayment", vatPaymentSchema);

// =====================================================================
// Phase R-6 — Expenses ledger + Profit Tax + Annual P&L (admin-only).
// Builds on R-5's tax tracking to surface a full annual P&L on the
// Annual Summary tab. Three collections, all admin-only access.
// =====================================================================

// ExpenseCategory — labels for the expense ledger. Seeded once at boot.
// Soft-delete (archived=true) preserves history when a category has been used;
// hard delete only when no Expense references it.
var expenseCategorySchema = new mongoose.Schema({
  name:     { type: String, required: true, unique: true, trim: true },
  archived: { type: Boolean, default: false }
}, { timestamps: true });
var ExpenseCategory = mongoose.model("ExpenseCategory", expenseCategorySchema);

// Expense — single ledger entry. amount is EGP (no currency field by design).
// date is a Date object; the /annual-pnl endpoint year-scopes via Cairo-local
// calendar (UTC+3 fixed range), matching R-5's nowCairo convention.
var expenseSchema = new mongoose.Schema({
  date:            { type: Date, required: true },
  categoryId:      { type: mongoose.Schema.Types.ObjectId, ref: "ExpenseCategory", required: true },
  amount:          { type: Number, required: true, min: 0 }, // > 0 enforced at write site
  description:     { type: String, default: "" },
  createdByUserId: { type: mongoose.Schema.Types.ObjectId, ref: "User", default: null }
}, { timestamps: true });
expenseSchema.index({ date: -1 });
expenseSchema.index({ categoryId: 1 });
var Expense = mongoose.model("Expense", expenseSchema);

// ProfitTaxConfig — admin-entered profit-tax rate for a given year. One row
// per year (unique). mode determines how value is applied at P&L time:
// percent → profitBeforeTax × value/100; fixed → value (EGP). The /annual-pnl
// endpoint clamps the computed amount to ≥ 0 (judgment call #2 — Phase R-6).
var profitTaxConfigSchema = new mongoose.Schema({
  year:            { type: Number, required: true, unique: true },
  mode:            { type: String, enum: ["percent", "fixed"], required: true },
  value:           { type: Number, required: true, min: 0 },
  updatedByUserId: { type: mongoose.Schema.Types.ObjectId, ref: "User", default: null }
}, { timestamps: true });
var ProfitTaxConfig = mongoose.model("ProfitTaxConfig", profitTaxConfigSchema);

// =====================================================================
// Phase R-12 — External brokers + external-deal commission split.
// Broker is a standalone reference collection (not an internal ARO User).
// Soft-delete (archived=true) preserves history when a Commission references
// the broker; hard delete only when no references exist. Future phases
// (R-12 Parts 2-7) wire this into Lead.dealType + Commission.externalSplit.
// =====================================================================
var brokerSchema = new mongoose.Schema({
  name:            { type: String, required: true, trim: true },
  phone:           { type: String, default: "" },
  email:           { type: String, default: "" },
  notes:           { type: String, default: "" },
  archived:        { type: Boolean, default: false },
  createdByUserId: { type: mongoose.Schema.Types.ObjectId, ref: "User", default: null }
}, { timestamps: true });
brokerSchema.index({ archived: 1, name: 1 });
var Broker = mongoose.model("Broker", brokerSchema);

// =====================================================================
// ATTENDANCE & SALARY SYSTEM — Phase 1 foundation
// Spec: docs/attendance-salary-requirements.md
//
// Settings live in AppSetting under key="attendance_settings" (reuses the
// existing key/value pattern next to "rotation", "projectWeights",
// "campaigns"). The schemas below cover the attendance/salary domain only.
// =====================================================================

// CompanyOffDay — a single calendar date that is off for everyone (e.g. Labor
// Day, company anniversary). date stored as start-of-day Africa/Cairo. Removed
// from each user's workingDays count when computing salary. Multi-day ranges
// (e.g. Eid) share a rangeId so the UI can group them and cascade-delete;
// salary calc remains per-day and ignores rangeId entirely.
var CompanyOffDay = mongoose.model("CompanyOffDay", new mongoose.Schema({
  date:      { type: Date, required: true, unique: true },
  name:      { type: String, required: true },
  createdBy: { type: mongoose.Schema.Types.ObjectId, ref: "User" },
  rangeId:   { type: mongoose.Schema.Types.ObjectId, default: null, index: true }
}, { timestamps: true }));

// Attendance — one document per user per calendar day. Created on check-in;
// stays open (status="in_progress") until check-out. status reflects late tier
// computed at check-in time. deductionFraction snapshots the cost as 0 / 0.25
// / 0.5 / 1. override is set only when an admin uses the Day Override tool.
var Attendance = mongoose.model("Attendance", new mongoose.Schema({
  userId: { type: mongoose.Schema.Types.ObjectId, ref: "User", required: true, index: true },
  date:   { type: Date, required: true, index: true },
  checkIn: {
    timestamp:       Date,
    latitude:        Number,
    longitude:       Number,
    distanceMeters:  Number,
    accuracyMeters:  Number,
    ipAddress:       String,
    deviceType:      String,
    isOffSite:       { type: Boolean, default: false },
    offSiteRequestId:{ type: mongoose.Schema.Types.ObjectId, ref: "OffSiteRequest" },
    // Multi-branch (2026-05-07) — name of the office location whose geofence
    // matched this check-in. Optional on legacy docs.
    locationName:    String
  },
  checkOut: {
    timestamp:       Date,
    latitude:        Number,
    longitude:       Number,
    distanceMeters:  Number,
    accuracyMeters:  Number,
    ipAddress:       String,
    deviceType:      String,
    isOffSite:       { type: Boolean, default: false },
    offSiteRequestId:{ type: mongoose.Schema.Types.ObjectId, ref: "OffSiteRequest" },
    locationName:    String
  },
  status: {
    type: String,
    enum: ["in_progress","present","late_quarter","late_half","late_full","absent","pending_offsite","override"],
    default: "in_progress"
  },
  deductionFraction: { type: Number, default: 0 },
  override: {
    action:            { type: String, enum: ["cancel_deduction","add_full_deduction","mark_off_day","apply_fraction"] },
    reason:            String,
    overriddenBy:      { type: mongoose.Schema.Types.ObjectId, ref: "User" },
    overriddenAt:      Date,
    sickLimitExceeded: { type: Boolean, default: false }
  },
  computedAt: { type: Date, default: Date.now }
}, { timestamps: true }));
Attendance.collection.createIndex({ userId: 1, date: 1 }, { unique: true }).catch(function(){});
// Date-only index — added Phase R-attendance for the team-view range query
// (single shared $gte/$lt scan when no userId filter is set).
Attendance.collection.createIndex({ date: 1 }).catch(function(){});

// OffSiteRequest — submitted when an employee is outside the geofence and needs
// a remote check-in/out approved. Created in "pending" state; an attendance
// record with status="pending_offsite" is also created at the same timestamp.
// Approval flips both records to their normal flow (present + late tier).
var OffSiteRequest = mongoose.model("OffSiteRequest", new mongoose.Schema({
  userId:        { type: mongoose.Schema.Types.ObjectId, ref: "User", required: true },
  type:          { type: String, enum: ["check_in","check_out"], required: true },
  requestedAt:   { type: Date, default: Date.now },
  latitude:      Number,
  longitude:     Number,
  reason:        { type: String, required: true },
  attachmentUrl: String,
  status:        { type: String, enum: ["pending","approved","rejected","cancelled"], default: "pending" },
  reviewedBy:    { type: mongoose.Schema.Types.ObjectId, ref: "User" },
  reviewedAt:    Date,
  reviewNotes:   String,
  attendanceId:  { type: mongoose.Schema.Types.ObjectId, ref: "Attendance" }
}, { timestamps: true }));
OffSiteRequest.collection.createIndex({ userId: 1, requestedAt: -1 }).catch(function(){});
OffSiteRequest.collection.createIndex({ status: 1, requestedAt: -1 }).catch(function(){});

// SalaryRecord — one document per user per (year, month). Stores the snapshot
// after computation; "finalized" locks it from further edits. baseSalary is
// snapshotted at compute time so future base-salary changes don't retro-apply.
var SalaryRecord = mongoose.model("SalaryRecord", new mongoose.Schema({
  userId:          { type: mongoose.Schema.Types.ObjectId, ref: "User", required: true },
  year:            { type: Number, required: true },
  month:           { type: Number, required: true }, // 1-12
  baseSalary:      Number,
  workingDays:     Number,
  dailyRate:       Number,
  deductionDays:   Number,
  totalDeductions: Number,
  netSalary:       Number,
  finalized:       { type: Boolean, default: false },
  finalizedBy:     { type: mongoose.Schema.Types.ObjectId, ref: "User" },
  finalizedAt:     Date,
  computedAt:      { type: Date, default: Date.now }
}, { timestamps: true }));
SalaryRecord.collection.createIndex({ userId: 1, year: 1, month: 1 }, { unique: true }).catch(function(){});

// AuditLog — separate from SettingsAudit (which is settings-flatten-diff only).
// This logs every sensitive attendance/salary mutation with before/after blobs
// and free-form flags. type is an open string so new actions can be added
// without a schema migration.
var AuditLog = mongoose.model("AuditLog", new mongoose.Schema({
  type:         { type: String, required: true },
  targetUserId: { type: mongoose.Schema.Types.ObjectId, ref: "User" },
  performedBy:  { type: mongoose.Schema.Types.ObjectId, ref: "User" },
  before:       { type: mongoose.Schema.Types.Mixed, default: {} },
  after:        { type: mongoose.Schema.Types.Mixed, default: {} },
  reason:       String,
  flags:        { type: mongoose.Schema.Types.Mixed, default: {} },
  ipAddress:    String,
  timestamp:    { type: Date, default: Date.now }
}));
AuditLog.collection.createIndex({ targetUserId: 1, timestamp: -1 }).catch(function(){});
AuditLog.collection.createIndex({ performedBy: 1, timestamp: -1 }).catch(function(){});
AuditLog.collection.createIndex({ type: 1, timestamp: -1 }).catch(function(){});

// Defaults applied when no AppSetting key="attendance_settings" doc exists yet
// (first server boot). Office is empty so the Owner must configure it before
// anyone can check in. All permission toggles default ON for sales_admin + hr
// per the doc's mockup; Owner can switch them off in /settings/permissions.
var DEFAULT_ATTENDANCE_SETTINGS = {
  companyLocations: [],
  permissions: {
    manageSalaries:         { salesAdmin: true, hr: true },
    manageAttendance:       { salesAdmin: true, hr: true },
    approveOffSiteRequests: { salesAdmin: true, hr: true },
    manageCompanyOffDays:   { salesAdmin: true, hr: true }
  }
};

// Read attendance_settings from AppSetting, merging the stored value over the
// defaults so missing keys don't crash callers. Always returns a plain object.
async function getAttendanceSettings() {
  var doc = await AppSetting.findOne({ key: "attendance_settings" }).lean();
  var stored = (doc && doc.value) || {};
  return {
    companyLocations: Array.isArray(stored.companyLocations) ? stored.companyLocations : DEFAULT_ATTENDANCE_SETTINGS.companyLocations,
    permissions: {
      manageSalaries:         Object.assign({}, DEFAULT_ATTENDANCE_SETTINGS.permissions.manageSalaries,         (stored.permissions || {}).manageSalaries         || {}),
      manageAttendance:       Object.assign({}, DEFAULT_ATTENDANCE_SETTINGS.permissions.manageAttendance,       (stored.permissions || {}).manageAttendance       || {}),
      approveOffSiteRequests: Object.assign({}, DEFAULT_ATTENDANCE_SETTINGS.permissions.approveOffSiteRequests, (stored.permissions || {}).approveOffSiteRequests || {}),
      manageCompanyOffDays:   Object.assign({}, DEFAULT_ATTENDANCE_SETTINGS.permissions.manageCompanyOffDays,   (stored.permissions || {}).manageCompanyOffDays   || {})
    }
  };
}

// Permission decision for a single (role, action) pair against a settings doc.
// Owner (admin) always passes. sales_admin and hr are gated by the toggle for
// that action. Every other role is denied — attendance/salary endpoints are
// admin-side, sales roles never use them.
function hasAttendancePermission(role, action, settings) {
  if (role === "admin") return true;
  if (!settings || !settings.permissions || !settings.permissions[action]) return false;
  if (role === "sales_admin") return settings.permissions[action].salesAdmin === true;
  if (role === "hr")          return settings.permissions[action].hr === true;
  return false;
}

// Express middleware factory — wraps hasAttendancePermission for use as a
// route guard. Attaches the loaded settings to req so handlers don't refetch.
function requireAttendancePermission(action) {
  return async function(req, res, next) {
    try {
      var settings = await getAttendanceSettings();
      if (!hasAttendancePermission(req.user.role, action, settings)) {
        return res.status(403).json({ error: "Permission denied", action: action });
      }
      req.attendanceSettings = settings;
      next();
    } catch (e) {
      console.error("[requireAttendancePermission]", e);
      res.status(500).json({ error: "Permission check failed" });
    }
  };
}

// Owner-only gate — used for routes that must NEVER be delegated (office
// location, permission toggles, unlocking finalized months, editing the base
// salary of sales_admin/hr roles).
function ownerOnly(req, res, next) {
  if (req.user.role !== "admin") return res.status(403).json({ error: "Owner only" });
  next();
}

// Flatten a plain object into dotted-path leaves. Arrays are treated as leaf
// values (compared as a whole) so an audit entry for "tiers.tier1.agents"
// captures the full before/after list in one row.
function flattenSettings(obj, prefix, out) {
  out = out || {};
  prefix = prefix || "";
  if (obj === null || obj === undefined) { if (prefix) out[prefix] = obj; return out; }
  if (Array.isArray(obj) || typeof obj !== "object" || obj instanceof Date) {
    if (prefix) out[prefix] = obj;
    return out;
  }
  var keys = Object.keys(obj);
  if (keys.length === 0) { if (prefix) out[prefix] = obj; return out; }
  keys.forEach(function(k){
    flattenSettings(obj[k], prefix ? prefix + "." + k : k, out);
  });
  return out;
}

// Rotation pointers are bumped on every lead rotation tick — excluded so they
// don't drown real admin edits in the audit log.
var AUDIT_IGNORE_FIELDS = {
  "lastAssignedIdx": true,
  "tiers.tier1.lastIdx": true,
  "tiers.tier2.lastIdx": true,
  "tiers.tier3.lastIdx": true
};

function diffSettings(prev, next) {
  var a = flattenSettings(prev || {});
  var b = flattenSettings(next || {});
  var paths = {};
  Object.keys(a).forEach(function(k){ paths[k] = true; });
  Object.keys(b).forEach(function(k){ paths[k] = true; });
  var changes = [];
  Object.keys(paths).forEach(function(p){
    if (AUDIT_IGNORE_FIELDS[p]) return;
    var oldV = a[p];
    var newV = b[p];
    if (JSON.stringify(oldV) === JSON.stringify(newV)) return;
    changes.push({ field: p, oldValue: oldV === undefined ? null : oldV, newValue: newV === undefined ? null : newV });
  });
  return changes;
}

// Phase A4-prep+ (2026-05-05): canonical Lead source list. Must mirror
// the frontend SOURCES at src/App.js:216 — kept in two places until A3
// (admin-editable list via AppSetting) ships. normalizeSource() coerces
// incoming source values onto canonical casing/spacing so /api/leads/
// inbound's historical .toLowerCase() and manual entries like "Snap Chat"
// stop fragmenting the bucket. Compares on a stripped key (lowercase,
// alphanumeric only) so "tik tok", "TikTok", "tiktok", "TIK-TOK" all
// resolve to canonical "TikTok". Unrecognized values pass through
// verbatim — preserves legacy data for cleanup via the bulk editor.
var SOURCES = ["Facebook", "TikTok", "Snapchat", "WhatsApp", "Google Ads", "Referral", "Website", "Direct Call", "Other"];
var SOURCE_NORM_MAP = (function(){
  var m = {};
  SOURCES.forEach(function(s){
    var key = String(s).toLowerCase().replace(/[^a-z0-9]/g, "");
    m[key] = s;
  });
  return m;
})();
function normalizeSource(input) {
  var trimmed = String(input == null ? "" : input).trim();
  if (!trimmed) return "";
  var key = trimmed.toLowerCase().replace(/[^a-z0-9]/g, "");
  if (key && SOURCE_NORM_MAP[key]) return SOURCE_NORM_MAP[key];
  return trimmed;
}

