// ===== DAILY REQUEST ROUTES =====
app.get("/api/daily-requests", auth, async function(req, res) {
  try {
    var query = {};
    // Optional ?archived=true|false filter. Absent param keeps the legacy
    // behaviour (returns everything) so the unmigrated DailyRequestsPage +
    // ArchivePage callers — which still filter client-side, partly for
    // legacy-localStorage migration safety — continue to work unchanged.
    // Lets future callers (and Phase-2 ArchivePage rework) skip archived
    // rows on the wire instead of after the round-trip.
    if (req.query.archived === "true") query.archived = true;
    else if (req.query.archived === "false") query.archived = { $ne: true };
    if (req.user.role === "sales") {
      // Strict ownership. Equality match already excludes null/missing, but we
      // spell out $exists + $ne: null explicitly so the intent is visible and
      // accidental regressions to a partial filter can't quietly re-admit
      // unassigned rows.
      query.agentId = new mongoose.Types.ObjectId(req.user.id);
      query.$and = [
        { agentId: { $exists: true } },
        { agentId: { $ne: null } }
      ];
    } else if (req.user.role === "team_leader") {
      // Team leader: only see their direct sales' requests
      var tlUser = await User.findById(req.user.id).lean();
      var tlVisibleIds = [tlUser._id];
      var tlSales = await User.find({ reportsTo: tlUser._id }).lean();
      tlSales.forEach(function(s){ tlVisibleIds.push(s._id); });
      query.agentId = { $in: tlVisibleIds };
    } else if (req.user.role === "manager") {
      // Manager: only assigned requests (no unassigned), filtered by team.
      // Previous implementation issued up to three sequential User.find calls
      // (TLs then sales-under-TLs) before the DR query could run; with even a
      // modest org tree this added 1-2s to every page open and was the main
      // source of the chrome-renders-then-table-spins symptom. Single
      // $graphLookup over reportsTo with maxDepth:2 collapses the head-manager
      // walk to one round trip; mid-manager branch stays a single find.
      var managerUser = await User.findById(req.user.id).lean();
      var visibleIds = [managerUser._id];
      if (!managerUser.reportsTo) {
        var sub = await User.aggregate([
          { $match: { _id: managerUser._id } },
          { $graphLookup: {
              from: "users",
              startWith: "$_id",
              connectFromField: "_id",
              connectToField: "reportsTo",
              as: "descendants",
              maxDepth: 2
          }},
          { $project: { "descendants._id": 1 } }
        ]);
        var descArr = (sub[0] && Array.isArray(sub[0].descendants)) ? sub[0].descendants : [];
        descArr.forEach(function(u){ visibleIds.push(u._id); });
      } else {
        var direct = await User.find({ reportsTo: managerUser._id }).lean();
        direct.forEach(function(s){ visibleIds.push(s._id); });
      }
      query.agentId = { $in: visibleIds }; // only assigned ones
    } else if (req.user.role === "director") {
      // Director: assigned requests where the agent is anywhere in the
      // director's reportsTo subtree (managers + TLs + sales). Single
      // helper call — no parallel walk to maintain.
      var dirScopedDrIds = await getScopedUserIds(req.user);
      query.agentId = { $in: dirScopedDrIds };
    }
    // Pagination — STEP 1 of the leads/DR scalability work. Backward
    // compatible by design: when no ?page/?limit/?all param is sent, returns
    // the legacy plain-array shape so the four pre-existing callers (boot
    // loadData, DailyRequestsPage, ArchivePage, fetchDRs WS fallback)
    // continue to work unchanged. When any pagination param is present,
    // switches to the same {data,total,page,totalPages} shape that
    // /api/leads has been returning for a while — picked over the
    // alternative {items,totalCount,...} shape for cross-endpoint
    // consistency (the planned FE pagination helper sees one contract).
    // ?all=1 is an explicit opt-in to the object shape without slicing.
    var hasLimit      = req.query.limit !== undefined && parseInt(req.query.limit) > 0;
    var hasPage       = req.query.page !== undefined;
    var explicitAll   = req.query.all === "1";
    var wantsObjShape = hasLimit || hasPage || explicitAll;
    var page          = parseInt(req.query.page) || 1;
    var limit         = hasLimit ? parseInt(req.query.limit) : 0;
    var skip          = hasLimit ? (page - 1) * limit : 0;

    // STEP 4-5 X1 — scope audit log. Mirrors /api/leads logging. The
    // computed `query.agentId` clause captures the role-derived scope
    // shape ($eq for sales, $in for TL/manager/director, undefined for
    // admin/sales_admin).
    console.log("[scope] /api/daily-requests role=" + req.user.role + " uid=" + req.user.id + " scopeAgent=" + JSON.stringify(query.agentId || null));

    var drQuery = DailyRequest.find(query)
      .populate("agentId", "name title")
      .sort({ createdAt: -1 });
    if (hasLimit) drQuery = drQuery.skip(skip).limit(limit);
    var requests = await drQuery;

    // STEP 3 — opt-in summary projection. DR's only heavy field is
    // eoiDocuments[] (Mixed array, present on EOI-converted DRs only).
    // Stripping is mutation-safe because each request is a fresh Mongoose
    // doc here; the in-memory representation is discarded after .json().
    // Absent param = no strip; existing 4 callers continue to receive the
    // full doc unchanged.
    if (req.query.fields === "summary" && Array.isArray(requests)) {
      requests.forEach(function(r){ if (r) r.eoiDocuments = undefined; });
    }

    if (!wantsObjShape) return res.json(requests);

    // Smart-skip on countDocuments — same shape as /api/leads above.
    // When the page already contains the entire result set, the count
    // round-trip is redundant.
    var total = !hasLimit
      ? requests.length
      : (page === 1 && requests.length < limit)
        ? requests.length
        : await DailyRequest.countDocuments(query);
    console.log("[/api/daily-requests pagination]",
      { page: page, limit: limit, total: total, role: req.user.role, archived: req.query.archived || "all" });
    res.json({
      data: requests,
      total: total,
      page: page,
      totalPages: hasLimit ? Math.ceil(total / limit) : 1
    });
  } catch(e) { res.status(500).json({ error: e.message }); }
});

app.post("/api/daily-requests", auth, async function(req, res) {
  try {
    var r = await DailyRequest.create({
      name: req.body.name, phone: req.body.phone,
      phone2: req.body.phone2 || "",
      email: req.body.email || "", budget: req.body.budget || "",
      propertyType: req.body.propertyType || "",
      unitType: req.body.unitType || "",
      area: req.body.area || "", notes: req.body.notes || "",
      agentId: req.body.agentId || req.user.id,
      callbackTime: req.body.callbackTime || "",
      status: req.body.status || "NewLead",
      lastActivityTime: new Date(),
      hadMeeting: req.body.status === "MeetingDone",
      meetingDoneAt: req.body.status === "MeetingDone" ? new Date() : null,
    });
    r = await DailyRequest.findById(r._id).populate("agentId", "name title");
    // Log creation as activity
    var createNote = "Added — Status: " + (req.body.status||"NewLead");
    if(req.body.notes) createNote += " | " + req.body.notes;
    await Activity.create({ userId: req.user.id, type: "note", note: createNote, leadId: r._id });
    res.json(r);
  } catch(e) { res.status(500).json({ error: e.message }); }
});

app.put("/api/daily-requests/bulk-reassign", auth, adminOnly, async function(req, res) {
  try {
    // Mirrors the leads-side restriction at /api/leads/bulk-reassign — bulk
    // reassign is admin/sales_admin only. Inline check overrides adminOnly's
    // legacy admission of manager/team_leader.
    if (req.user.role !== "admin" && req.user.role !== "sales_admin") {
      return res.status(403).json({ error: "Bulk reassign is restricted to admin and sales_admin" });
    }
    var { leadIds, agentId } = req.body;
    if(!leadIds||!leadIds.length||!agentId) return res.status(400).json({ error: "leadIds and agentId required" });
    var agentObjId = new mongoose.Types.ObjectId(agentId);
    await DailyRequest.updateMany({ _id: { $in: leadIds } }, { $set: { agentId: agentObjId } });
    // Re-read the affected DRs so the broadcast carries usable data — without
    // this the dr_updated event has an empty payload and every connected
    // client falls back to a full /api/daily-requests refetch (App.js
    // line 15546). For a 50-DR bulk reassign with 10 agents online that's
    // 10 full-list refetches; with the docs included the broadcast handler
    // upserts in place.
    var updated = await DailyRequest.find({ _id: { $in: leadIds } }).populate("agentId", "name title").lean();
    res.json({ ok: true, count: leadIds.length, drs: updated });
  } catch(e) { res.status(500).json({ error: e.message }); }
});

// ===== STEP 4-1 — DR SEARCH + BY-PHONE LOOKUP =====
// Server-side replacements for the in-memory p.dailyRequests.filter scans
// in HeaderSearch, QuickPhoneSearch, and ActivityListPage routing. Same
// role-scoping as the DR list endpoint. Registered BEFORE :id so Express
// doesn't ObjectId-cast "search" / "by-phone".

var DR_SEARCH_FIELDS = "_id name phone phone2 email status eoiStatus dealStatus agentId archived budget propertyType area callbackTime lastActivityTime notes";

async function buildDRSearchScopeQuery(req) {
  var role = req.user.role;
  if (role === "sales") {
    return { agentId: new mongoose.Types.ObjectId(req.user.id) };
  }
  if (role === "team_leader") {
    var tlUser = await User.findById(req.user.id).lean();
    if (!tlUser) return { _id: null };
    var visibleIds = [tlUser._id];
    var tlSales = await User.find({ reportsTo: tlUser._id }).lean();
    tlSales.forEach(function(s){ visibleIds.push(s._id); });
    return { agentId: { $in: visibleIds } };
  }
  if (role === "manager" || role === "director") {
    var ids = await getScopedUserIds(req.user);
    if (!ids || ids.length === 0) return { _id: null };
    return { agentId: { $in: ids } };
  }
  return {}; // admin / sales_admin: unrestricted
}

app.get("/api/daily-requests/search", auth, async function(req, res) {
  try {
    var q = String(req.query.q || "").trim();
    if (q.length < 2) return res.json([]);
    var limit = Math.min(parseInt(req.query.limit) || 20, 50);
    var rx = new RegExp(q.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"), "i");
    var scope = await buildDRSearchScopeQuery(req);
    var query = { $and: [
      scope,
      { archived: { $ne: true } },
      { $or: [{ name: rx }, { phone: rx }, { phone2: rx }, { email: rx }, { notes: rx }, { propertyType: rx }, { area: rx }] }
    ]};
    var rows = await DailyRequest.find(query)
      .select(DR_SEARCH_FIELDS)
      .populate("agentId", "name title")
      .sort({ createdAt: -1 })
      .limit(limit)
      .lean();
    res.json(rows);
  } catch (e) {
    console.error("[GET /api/daily-requests/search]", e && e.message);
    res.status(500).json({ error: e && e.message ? e.message : "search_failed" });
  }
});

app.get("/api/daily-requests/by-phone", auth, async function(req, res) {
  try {
    var phone = String(req.query.phone || "").trim();
    if (phone.length < 4) return res.json([]);
    var limit = Math.min(parseInt(req.query.limit) || 20, 50);
    var rx = new RegExp(phone.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"));
    var scope = await buildDRSearchScopeQuery(req);
    var query = { $and: [
      scope,
      { $or: [{ phone: rx }, { phone2: rx }] }
    ]};
    var rows = await DailyRequest.find(query)
      .select(DR_SEARCH_FIELDS)
      .populate("agentId", "name title")
      .sort({ createdAt: -1 })
      .limit(limit)
      .lean();
    res.json(rows);
  } catch (e) {
    console.error("[GET /api/daily-requests/by-phone]", e && e.message);
    res.status(500).json({ error: e && e.message ? e.message : "by_phone_failed" });
  }
});

// STEP 4-2 — DR callbacks endpoint. Mirror of /api/leads/callbacks for DRs.
// DR has no assignments[] array — the top-level status/callbackTime IS the
// authoritative state, so the query is straightforward. Default exclude
// matches the FE bell's DR filter (DoneDeal-ish + Deal Cancelled + Not Int.).
var DR_CALLBACK_FIELDS = "_id name phone phone2 status agentId archived callbackTime lastActivityTime";
var DEFAULT_DR_CB_EXCLUDE = ["DoneDeal", "Done Deal", "Deal Cancelled", "NotInterested"];

app.get("/api/daily-requests/callbacks", auth, async function(req, res) {
  try {
    var from = req.query.from ? String(req.query.from) : null;
    var to   = req.query.to   ? String(req.query.to)   : null;
    var excludeStatuses = req.query.excludeStatuses
      ? parseExcludeStatuses(req.query.excludeStatuses)
      : DEFAULT_DR_CB_EXCLUDE;
    var limit = Math.min(parseInt(req.query.limit) || 500, 2000);
    // Default DESC — symmetric to /api/leads/callbacks.
    var order = req.query.order === "asc" ? 1 : -1;
    var countOnly = req.query.count_only === "true" || req.query.count_only === "1";
    var scope = await buildDRSearchScopeQuery(req);

    var cbCond = { $type: "string", $gt: "" };
    if (from) cbCond.$gte = from;
    if (to)   cbCond.$lte = to;
    var ands = [
      scope,
      { archived: { $ne: true } },
      { callbackTime: cbCond },
      // Same lastActivityTime <= callbackTime filter as the Leads variant —
      // see /api/leads/callbacks comment for the qualification rule.
      { $expr: {
        $let: {
          vars: { cbDate: { $convert: { input: "$callbackTime", to: "date", onError: null, onNull: null } } },
          in: { $and: [
            { $ne: ["$$cbDate", null] },
            { $lte: [{ $ifNull: ["$lastActivityTime", new Date(0)] }, "$$cbDate"] }
          ]}
        }
      }}
    ];
    if (excludeStatuses.length) ands.push({ status: { $nin: excludeStatuses } });
    var query = { $and: ands };

    if (countOnly) {
      var count = await DailyRequest.countDocuments(query);
      return res.json({ count: count });
    }
    var rows = await DailyRequest.find(query)
      .select(DR_CALLBACK_FIELDS)
      .populate("agentId", "name title")
      .sort({ callbackTime: order })
      .limit(limit)
      .lean();
    res.json(rows);
  } catch (e) {
    console.error("[GET /api/daily-requests/callbacks]", e && e.message);
    res.status(500).json({ error: e && e.message ? e.message : "callbacks_failed" });
  }
});

// STEP 4-3 — DR counts endpoint. Mirror of /api/leads/counts for the DR
// collection. Role-scoped via buildDRSearchScopeQuery. Date semantics match
// the lead version. DR has no assignments[] array so interested is computed
// against the top-level status only.
app.get("/api/daily-requests/counts", auth, async function(req, res) {
  try {
    var from = req.query.from ? new Date(String(req.query.from)) : null;
    var to   = req.query.to   ? new Date(String(req.query.to))   : null;
    if (from && isNaN(from.getTime())) from = null;
    if (to   && isNaN(to.getTime()))   to   = null;
    var fromIso = from ? from.toISOString() : null;
    var toIso   = to   ? to.toISOString()   : null;
    var nowIso  = new Date().toISOString();
    var scope = await buildDRSearchScopeQuery(req);

    var createdInWindow = {};
    if (from || to) {
      createdInWindow.createdAt = {};
      if (from) createdInWindow.createdAt.$gte = from;
      if (to)   createdInWindow.createdAt.$lte = to;
    }
    var baseAnd = [scope, { archived: { $ne: true } }];
    if (from || to) baseAnd.push(createdInWindow);

    var cbCondInWindow = { $type: "string", $gt: "" };
    if (fromIso) cbCondInWindow.$gte = fromIso;
    if (toIso)   cbCondInWindow.$lte = toIso;
    var cbOverdueCond = Object.assign({}, cbCondInWindow, { $lt: nowIso });

    // DR statuses observed in production: "Meeting"|"MeetingDone" for meetings;
    // "DoneDeal"|"Done Deal"|"Deal" for deals.
    var meetingsCond = { status: { $in: ["Meeting", "MeetingDone", "Meeting Done"] } };
    var dealsCond    = { status: { $in: ["DoneDeal", "Done Deal", "Deal"] } };

    var counts = await Promise.all([
      DailyRequest.countDocuments({ $and: baseAnd }),
      DailyRequest.countDocuments({ $and: baseAnd.concat([meetingsCond]) }),
      DailyRequest.countDocuments({ $and: baseAnd.concat([dealsCond]) }),
      DailyRequest.countDocuments({ $and: [scope, { archived: { $ne: true } }, { callbackTime: cbCondInWindow }] }),
      DailyRequest.countDocuments({ $and: [scope,
        { archived: { $ne: true } },
        { callbackTime: cbOverdueCond },
        { status: { $nin: ["Meeting", "MeetingDone", "DoneDeal", "Done Deal", "Deal", "Deal Cancelled"] } }
      ]})
    ]);

    res.json({
      total:            counts[0],
      meetings:         counts[1],
      deals:            counts[2],
      callbacksInRange: counts[3],
      overdueCallbacks: counts[4]
    });
  } catch (e) {
    console.error("[GET /api/daily-requests/counts]", e && e.message);
    res.status(500).json({ error: e && e.message ? e.message : "dr_counts_failed" });
  }
});

// STEP 4-3 — DR per-agent stats for AgentPerf / TeamPage. Admin/sales_admin
// only — same access tier as the existing /api/dashboard/admin-stats. Returns
// `{ perAgent: [{uid, drs, meetings, deals}], total: N }` aggregated server-
// side via $group on agentId so 50 sales × ~1k DRs no longer round-trip an
// in-memory bucket on the client.
app.get("/api/dashboard/dr-stats", auth, async function(req, res) {
  try {
    if (req.user.role !== "admin" && req.user.role !== "sales_admin") {
      return res.status(403).json({ error: "Admin only" });
    }
    var from = req.query.from ? new Date(String(req.query.from)) : null;
    var to   = req.query.to   ? new Date(String(req.query.to))   : null;
    if (from && isNaN(from.getTime())) from = null;
    if (to   && isNaN(to.getTime()))   to   = null;

    var match = { archived: { $ne: true } };
    if (from || to) {
      match.createdAt = {};
      if (from) match.createdAt.$gte = from;
      if (to)   match.createdAt.$lte = to;
    }

    var pipeline = [
      { $match: match },
      { $group: {
        _id: "$agentId",
        drs: { $sum: 1 },
        meetings: { $sum: { $cond: [{ $in: ["$status", ["Meeting", "MeetingDone", "Meeting Done"]] }, 1, 0] } },
        deals:    { $sum: { $cond: [{ $in: ["$status", ["DoneDeal", "Done Deal", "Deal"]] }, 1, 0] } }
      }},
      { $lookup: { from: "users", localField: "_id", foreignField: "_id", as: "agent" } },
      { $project: {
        _id: 0,
        uid:  { $ifNull: [{ $toString: "$_id" }, "" ] },
        name: { $ifNull: [{ $arrayElemAt: ["$agent.name", 0] }, ""] },
        drs: 1, meetings: 1, deals: 1
      }},
      { $sort: { drs: -1 } }
    ];

    var perAgent = await DailyRequest.aggregate(pipeline);
    var total = perAgent.reduce(function(s,r){ return s + (r.drs || 0); }, 0);
    res.json({ perAgent: perAgent, total: total });
  } catch (e) {
    console.error("[GET /api/dashboard/dr-stats]", e && e.message);
    res.status(500).json({ error: e && e.message ? e.message : "dr_stats_failed" });
  }
});

// STEP 4-5 X2 — distinct source values across archived leads. Replaces the
// in-memory ArchivePage.legacy-source scan at App.js L3641-3648, which after
// the X3 bootstrap shrink would only see ~100 leads' sources. Admin-only
