// STEP 4-5 X2 — TeamPage MemberCard quarterly aggregation. One round-trip
// for every member instead of N parallel /api/agents/:id/quarterly-stats
// calls. Mirrors the FE getQTargets + per-card matchesAgent + qDeals/qRev/
// qLeads/qCalls derivations.
//
// Returns: { members: [{
//   uid, name, role, qTarget, qDeals, qLeads, qCalls, qRev, qProg,
//   isManagerCard, teamUids: []
// }] }
//
// Scope rule (same as TeamPage's visibleManagers logic):
//   - admin / sales_admin: every manager + team_leader + their direct sales
//   - manager: self + own team subtree
//   - team_leader: self + direct sales
//   - sales / viewer / hr / director / other: 403
app.get("/api/team/member-stats", auth, async function(req, res) {
  try {
    var role = req.user.role;
    if (role !== "admin" && role !== "sales_admin" && role !== "manager" && role !== "team_leader" && role !== "director") {
      return res.status(403).json({ error: "Team stats not available for this role" });
    }
    var nowDate = new Date();
    var year    = parseInt(req.query.year)    || nowDate.getUTCFullYear();
    var quarter = parseInt(req.query.quarter) || (Math.floor(nowDate.getUTCMonth()/3) + 1);
    if (quarter < 1 || quarter > 4) return res.status(400).json({ error: "quarter must be 1..4" });
    var qStart = new Date(Date.UTC(year, (quarter-1)*3, 1, 0,0,0,0));
    var qEnd   = new Date(Date.UTC(year, quarter*3, 1, 0,0,0,0));
    console.log("[scope] /api/team/member-stats role=" + role + " uid=" + req.user.id + " year=" + year + " q=" + quarter);

    // Resolve the visible user pool by role
    var visibleQuery;
    if (role === "admin" || role === "sales_admin") {
      visibleQuery = { active: { $ne: false }, role: { $in: ["sales", "team_leader", "manager"] } };
    } else if (role === "manager" || role === "director") {
      var scopedIds = await getScopedUserIds(req.user) || [];
      if (scopedIds.length === 0) return res.status(403).json({ error: "Scope unavailable" });
      visibleQuery = { _id: { $in: scopedIds } };
    } else {
      var meUid = new mongoose.Types.ObjectId(req.user.id);
      var directs = await User.find({ reportsTo: meUid }).select("_id").lean();
      var ids = [meUid].concat(directs.map(function(u){ return u._id; }));
      visibleQuery = { _id: { $in: ids } };
    }
    var members = await User.find(visibleQuery).select("_id name role qTargets reportsTo").lean();

    // Pre-fetch project-weights map (single AppSetting read)
    var pwDoc = await AppSetting.findOne({ key: "projectWeights" }).lean();
    var pwMap = (pwDoc && pwDoc.value && typeof pwDoc.value === "object") ? pwDoc.value : {};

    // Per-member quarterly aggregation. For each user, build agentOids set
    // (self + direct sales subordinates for manager/TL cards) and aggregate
    // deals + leads + calls in the quarter.
    var memberById = {};
    members.forEach(function(u){ memberById[String(u._id)] = u; });

    // Phase X3 perf — parallelize per-member work. Promise.all over members
    // so every card's queries fly concurrently; inside each member the three
    // count queries (qLeads / dealRows / qCalls) have no inter-dependencies
    // so they Promise.all too. For manager/TL cards the two User.find lookups
    // (subs + teamForTarget) feed agentOids/qTarget and must complete before
    // the count queries can issue — but the two User.finds run in parallel
    // with each other. Net serial chain per member drops from ~5 round-trips
    // to 1 (sales) or 2 (manager/TL).
    var results = await Promise.all(members.map(async function(u) {
      var uid = u._id;
      var isManagerCard = u.role === "manager" || u.role === "team_leader";
      var agentOids = [uid];
      var qTarget = 0;
      if (isManagerCard) {
        var [subs, teamForTarget] = await Promise.all([
          User.find({ active: { $ne: false }, role: { $in: ["sales", "team_leader"] }, reportsTo: uid }).select("_id").lean(),
          User.find({ active: { $ne: false }, role: { $in: ["sales", "team_leader"] }, reportsTo: uid }).select("qTargets").lean()
        ]);
        subs.forEach(function(s){ agentOids.push(s._id); });
        qTarget = teamForTarget.reduce(function(s,m){ return s + (readQTargetServer(m, year, quarter) || 0); }, 0);
        if (!qTarget) qTarget = readQTargetServer(u, year, quarter) || 0;
      } else {
        qTarget = readQTargetServer(u, year, quarter) || 0;
      }

      // Leads / Deals / Revenue via the shared helper (single source of truth,
      // also used by /api/reports/overview/agents). Calls stay inline here.
      var statsAndCalls = await Promise.all([
        computeAgentDealStats(agentOids, qStart, qEnd, pwMap),
        Activity.countDocuments({
          userId: { $in: agentOids },
          type: "call",
          createdAt: { $gte: qStart, $lt: qEnd }
        })
      ]);
      var dealStats = statsAndCalls[0];
      var qCalls    = statsAndCalls[1];
      var qLeads    = dealStats.leads;
      var qDeals    = dealStats.deals;
      var qRev      = dealStats.revenue;

      var qProg = qTarget > 0 ? Math.min(100, Math.round((qRev / qTarget) * 100)) : 0;

      return {
        uid: String(uid),
        name: u.name || "",
        role: u.role,
        isManagerCard: isManagerCard,
        teamUids: agentOids.map(function(o){ return String(o); }),
        qTarget: qTarget,
        qLeads: qLeads,
        qDeals: qDeals,
        qCalls: qCalls,
        qRev: qRev,
        qProg: qProg
      };
    }));

    res.json({ year: year, quarter: quarter, members: results });
  } catch (e) {
    console.error("[GET /api/team/member-stats]", e && e.message);
    res.status(500).json({ error: e && e.message ? e.message : "member_stats_failed" });
  }
});

// STEP 4-5 X2 — Dashboard AgentPerf table. Replaces the in-memory
// agentPerfMemo (App.js L7336-7484) which scans p.leads + p.dailyReqs +
// p.activities to build a per-agent stats table. Admin / sales_admin /
// manager / team_leader / director only.
//
// Algorithm ports the FE memo's 4-pass structure to server-side JS using
// the full collections the server already has access to. Filter range
// passed via ?from=&to= (ms epoch — keeps the FE call site identical).
app.get("/api/dashboard/agent-perf", auth, async function(req, res) {
  try {
    var role = req.user.role;
    if (role === "sales" || role === "viewer" || role === "hr") {
      return res.status(403).json({ error: "AgentPerf not available for this role" });
    }
    var rsA = parseInt(req.query.from) || 0;
    var reA = parseInt(req.query.to) || Date.now();
    console.log("[scope] /api/dashboard/agent-perf role=" + role + " uid=" + req.user.id + " from=" + rsA + " to=" + reA);

    // Visible users — sales role for the rows (matches FE filter at L7367).
    // Scope: admin / sales_admin sees every active sales agent; TL/manager/
    // director sees their subtree.
    var salesQuery = { active: { $ne: false }, role: "sales" };
    if (role === "team_leader" || role === "manager" || role === "director") {
      var scopedIds = await getScopedUserIds(req.user) || [];
      if (scopedIds.length === 0) return res.status(403).json({ error: "Scope unavailable" });
      salesQuery._id = { $in: scopedIds };
    }
    var users = await User.find(salesQuery).select("_id name").lean();
    if (!users.length) return res.json({ rows: [] });

    // Collection slices for the range. Same patterns as FE memo passes.
    var leads = await Lead.find({
      archived: { $ne: true }
    }).select("_id name status callbackTime lastActivityTime agentId splitAgent2Id createdAt assignments agentHistory globalStatus").lean();

    var dailyReqs = await DailyRequest.find({
      archived: { $ne: true },
      createdAt: { $gte: new Date(rsA), $lte: new Date(reA) }
    }).select("_id name agentId createdAt").lean();

    var activities = await Activity.find({
      createdAt: { $gte: new Date(rsA), $lte: new Date(reA) }
    }).select("_id userId leadId type note createdAt").lean();

    var now = Date.now();
    var interestedStatusesA = ["Interested", "Hot Case", "HotCase", "Potential"];

    // Pass 1: bucket leads by agentId via assignments in range, plus
    // rotation in/out tallies by NAME (agentHistory keys on name).
    var alByAgent = new Map();
    var rotOutByName = new Map(), rotInByName = new Map();
    for (var i = 0; i < leads.length; i++) {
      var l = leads[i];
      var assigns = l.assignments;
      if (assigns && assigns.length) {
        var added = null;
        for (var j = 0; j < assigns.length; j++) {
          var a = assigns[j];
          var rawAid = a.agentId && a.agentId._id ? a.agentId._id : a.agentId;
          if (!rawAid) continue;
          var aidStr = String(rawAid);
          if (added && added.has(aidStr)) continue;
          var t = a.assignedAt ? new Date(a.assignedAt).getTime() : 0;
          if (!isNaN(t) && t >= rsA && t <= reA) {
            if (!added) added = new Set();
            added.add(aidStr);
            var arr = alByAgent.get(aidStr);
            if (!arr) { arr = []; alByAgent.set(aidStr, arr); }
            arr.push(l);
          }
        }
      }
      var hist = l.agentHistory;
      if (hist && hist.length) {
        var froms = null, tos = null;
        for (var k = 0; k < hist.length; k++) {
          var h = hist[k];
          if (!h || h.action !== "Rotation") continue;
          if (h.fromAgent) { if (!froms) froms = new Set(); froms.add(h.fromAgent); }
          if (h.toAgent)   { if (!tos)   tos   = new Set(); tos.add(h.toAgent); }
        }
        if (froms) froms.forEach(function(name){ rotOutByName.set(name, (rotOutByName.get(name)||0)+1); });
        if (tos)   tos.forEach(function(name){   rotInByName.set(name,  (rotInByName.get(name)||0)+1); });
      }
    }

    // Pass 2: DRs by agentId
    var drsByAgent = new Map();
    for (var d = 0; d < dailyReqs.length; d++) {
      var r = dailyReqs[d];
      var raid = r.agentId && r.agentId._id ? r.agentId._id : r.agentId;
      if (!raid) continue;
      var raidStr = String(raid);
      var arrR = drsByAgent.get(raidStr);
      if (!arrR) { arrR = []; drsByAgent.set(raidStr, arrR); }
      arrR.push(r);
    }

    // Pass 3: activities by userId
    var actsByAgent = new Map();
    var actCallsByAgent = new Map();
    for (var x = 0; x < activities.length; x++) {
      var act = activities[x];
      var xaid = act.userId && act.userId._id ? act.userId._id : act.userId;
      if (!xaid) continue;
      var xidStr = String(xaid);
      var aarr = actsByAgent.get(xidStr);
      if (!aarr) { aarr = []; actsByAgent.set(xidStr, aarr); }
      aarr.push(act);
      if (act.type === "call" || ((act.note || "").toLowerCase().indexOf("call") >= 0)) {
        actCallsByAgent.set(xidStr, (actCallsByAgent.get(xidStr) || 0) + 1);
      }
    }

    // Pass 4: per-user metrics
    var rows = users.map(function(u){
      var uid = String(u._id);
      var uname = u.name || "";
      var al = alByAgent.get(uid) || [];
      var adr = drsByAgent.get(uid) || [];
      var aActs = actsByAgent.get(uid) || [];
      var acalls = actCallsByAgent.get(uid) || 0;
      var arotOut = rotOutByName.get(uname) || 0;
      var arotIn  = rotInByName.get(uname) || 0;

      var aint = 0, ameet = 0, anoAns = 0, afup = 0, aover = 0, adeals = 0, aFbLeads = 0;
      var rtSum = 0, rtCount = 0;
      for (var ai = 0; ai < al.length; ai++) {
        var lead = al[ai];
        var hasInt = false, hasMeet = false, hasNoAns = false, hasAgentFb = false;
        var lassigns = lead.assignments;
        if (lassigns) {
          for (var aj = 0; aj < lassigns.length; aj++) {
            var asg = lassigns[aj];
            var asgAid = asg.agentId && asg.agentId._id ? asg.agentId._id : asg.agentId;
            if (String(asgAid) !== uid) continue;
            var asgSt = asg.status;
            if (!hasInt && interestedStatusesA.indexOf(asgSt) >= 0) hasInt = true;
            if (!hasMeet && (asgSt === "Meeting Done" || asgSt === "MeetingDone")) hasMeet = true;
            if (!hasNoAns && (asgSt === "NoAnswer" || asgSt === "No Answer")) hasNoAns = true;
            if (!hasAgentFb) {
              if ((asg.notes && String(asg.notes).trim().length > 0) || (asg.lastFeedback && String(asg.lastFeedback).trim().length > 0)) hasAgentFb = true;
            }
            if (asg.lastActionAt && lead.createdAt) {
              var diff = new Date(asg.lastActionAt).getTime() - new Date(lead.createdAt).getTime();
              if (diff >= 0) { rtSum += diff; rtCount++; }
            }
          }
        }
        if (hasInt) aint++;
        if (hasMeet) ameet++;
        if (hasNoAns) anoAns++;
        if (lead.callbackTime) {
          afup++;
          if (new Date(lead.callbackTime).getTime() < now && ["MeetingDone","DoneDeal","EOI"].indexOf(lead.status) === -1) aover++;
        }
        if (lead.status === "DoneDeal" || lead.globalStatus === "donedeal") adeals++;
        var leadLevelFb = (lead.notes && String(lead.notes).trim().length > 0) || (lead.lastFeedback && String(lead.lastFeedback).trim().length > 0);
        if (leadLevelFb || hasAgentFb) aFbLeads++;
      }

      var fbPct = al.length > 0 ? (aFbLeads / al.length) : 0;
      var respH = rtCount > 0 ? (rtSum / rtCount) / 3600000 : 0;
      var ip = al.length > 0 ? Math.round(aint / al.length * 100) : 0;
      var mp = al.length > 0 ? Math.round(ameet / al.length * 100) : 0;
      var cbTotal = afup;
      var cbOnTime = afup - aover;
      var cbPct = cbTotal > 0 ? (cbOnTime / cbTotal) : (afup === 0 ? 1 : 0);
      var qActivity = al.length > 0 ? Math.min(25, (aActs.length / al.length) * 25) : 0;
      var qFeedback = fbPct * 20;
      var qResp = respH > 0 ? Math.max(0, 20 - respH * 2) : (rtCount > 0 ? 20 : 10);
      var qMeeting = al.length > 0 ? Math.min(15, (ameet / al.length) * 100 * 0.15) : 0;
      var qCallback = cbPct * 20;
      var qualityScore = Math.round(qActivity + qFeedback + qResp + qMeeting + qCallback);
      if (qualityScore > 100) qualityScore = 100;
      if (qualityScore < 0)   qualityScore = 0;
      var actScore = Math.min(100, (al.length + adr.length) * 5);
      var rtScore  = respH > 0 ? Math.max(0, 100 - respH * 2) : 50;
      var score = Math.round(actScore * 0.4 + mp * 0.3 + ip * 0.2 + rtScore * 0.1);
      return {
        uid: uid, name: u.name, leads: al.length, dr: adr.length,
        total: al.length + adr.length, calls: acalls, followups: afup,
        overdue: aover, interested: aint, ip: ip, meetings: ameet, mp: mp,
        deals: adeals, rotOut: arotOut, rotIn: arotIn, noAnswer: anoAns,
        respTime: respH > 0 ? respH.toFixed(1) : "—",
        score: score, quality: qualityScore
      };
    }).sort(function(a, b){ return b.quality - a.quality; });

    res.json({ rows: rows });
  } catch (e) {
    console.error("[GET /api/dashboard/agent-perf]", e && e.message);
    res.status(500).json({ error: e && e.message ? e.message : "agent_perf_failed" });
  }
});

// STEP 4-5 X2 — KPIsPage chart data + status distribution. Replaces the
// in-memory myLeads.filter / myDeals.filter scans on KPIsPage that would
// silently miss data after the X3 bootstrap shrink. Returns:
//   { byStatus: { NewLead, Potential, HotCase, CallBack, MeetingDone,
//                  NotInterested, NoAnswer, DoneDeal, EOI },
//     totals:   { leads, deals, calls } }
//
// Access: self, OR admin/sales_admin, OR a TL/manager/director whose
// getScopedUserIds() includes the target. For manager/TL targets, the
// counts span the team subtree (matches FE KPIsPage TL/manager view).
app.get("/api/agents/:id([0-9a-fA-F]{24})/my-stats", auth, async function(req, res) {
  try {
    var targetId = req.params.id;
    var role = req.user.role;
    var uid = String(req.user.id);
    var isSelf = uid === targetId;
    var isAdminTier = role === "admin" || role === "sales_admin";
    var hasAccess = isSelf || isAdminTier;
    if (!hasAccess && (role === "team_leader" || role === "manager" || role === "director")) {
      var scopedIds = await getScopedUserIds(req.user) || [];
      hasAccess = scopedIds.some(function(id){ return String(id) === targetId; });
    }
    if (!hasAccess) return res.status(403).json({ error: "Forbidden" });

    var target = await User.findById(targetId).select("_id name role").lean();
    if (!target) return res.status(404).json({ error: "Agent not found" });

    // Resolve agent set — subtree for manager/TL, self for sales.
    var oid = new mongoose.Types.ObjectId(targetId);
    var agentOids = [oid];
    if (target.role === "manager" || target.role === "team_leader") {
      var team = await User.find({ active: { $ne: false }, role: { $in: ["sales", "team_leader"] }, reportsTo: target._id }).select("_id").lean();
      team.forEach(function(u){ agentOids.push(u._id); });
    }
    console.log("[scope] /api/agents/:id/my-stats role=" + role + " uid=" + uid + " target=" + targetId + " targetRole=" + target.role + " agentSetSize=" + agentOids.length);

    // Aggregate status counts. archived excluded; "Daily Request" source
    // excluded (matches FE myLeads filter at App.js L18954).
    var match = {
      archived: { $ne: true },
      source: { $ne: "Daily Request" },
      $or: [{ agentId: { $in: agentOids } }, { splitAgent2Id: { $in: agentOids } }]
    };
    var groupRows = await Lead.aggregate([
      { $match: match },
      { $group: { _id: "$status", count: { $sum: 1 } } }
    ]);
    var byStatus = { NewLead: 0, Potential: 0, HotCase: 0, CallBack: 0, MeetingDone: 0, NotInterested: 0, NoAnswer: 0, DoneDeal: 0, EOI: 0 };
    var totalLeads = 0;
    groupRows.forEach(function(g){
      var key = g._id;
      if (key === "Meeting Done") key = "MeetingDone";
      if (key === "Hot Case")     key = "HotCase";
      if (key === "Not Interested") key = "NotInterested";
      if (key === "No Answer")    key = "NoAnswer";
      if (byStatus[key] !== undefined) byStatus[key] = (byStatus[key] || 0) + (g.count || 0);
      totalLeads += g.count || 0;
    });
    var deals = byStatus.DoneDeal || 0;
    var calls = await Activity.countDocuments({ userId: { $in: agentOids }, type: "call" });

    res.json({
      uid: targetId, name: target.name || "", role: target.role || "",
      byStatus: byStatus,
      totals: { leads: totalLeads, deals: deals, calls: calls }
    });
  } catch (e) {
    console.error("[GET /api/agents/:id/my-stats]", e && e.message);
    res.status(500).json({ error: e && e.message ? e.message : "my_stats_failed" });
  }
});

// STEP 4-3 — Per-agent quarterly stats. Replaces the in-memory KPIsPage and
// TeamPage MemberCard scans that compute qLeads / qDeals / qCalls / qRev /
// qTarget from p.leads + p.activities + p.users. Once STEP 4-5 shrinks the
// bootstrap those scans would silently miss most of the quarter's history.
//
// Effective qTarget mirrors the FE getEffectiveQTarget: manager/team_leader
// with subordinates → sum of subordinates' qTargets; otherwise own qTarget.
// Year-aware via readQTargetServer.
//
// qRev is the raw budget sum for DoneDeal leads in the quarter (by dealDate
// fallback chain: dealDate → eoiDate → updatedAt → createdAt). Project
// weight and split halving are NOT applied here — the FE multiplies
// projectWeight × split factor at render time, matching the existing
// KPIsPage / TeamPage formulas. Returning the raw sum keeps the endpoint
// scope-agnostic (no need to embed project-weights/split logic server-side
// that the FE already owns).
app.get("/api/agents/:id([0-9a-fA-F]{24})/quarterly-stats", auth, async function(req, res) {
  try {
    var targetId = req.params.id;
    var nowDate = new Date();
    var year    = parseInt(req.query.year)    || nowDate.getUTCFullYear();
    var quarter = parseInt(req.query.quarter) || (Math.floor(nowDate.getUTCMonth()/3) + 1);
    if (quarter < 1 || quarter > 4) return res.status(400).json({ error: "quarter must be 1..4" });
    var qStart = new Date(Date.UTC(year, (quarter-1)*3, 1, 0, 0, 0, 0));
    var qEnd   = new Date(Date.UTC(year, quarter*3, 1, 0, 0, 0, 0));

    // Access: self, OR admin/sales_admin, OR a TL/manager/director whose
    // scope (per getScopedUserIds) includes targetId.
    var uid = String(req.user.id);
    var role = req.user.role;
    var isSelf = uid === targetId;
    var isAdminTier = role === "admin" || role === "sales_admin";
    var hasAccess = isSelf || isAdminTier;
    if (!hasAccess && (role === "team_leader" || role === "manager" || role === "director")) {
      var scopedIds = await getScopedUserIds(req.user) || [];
      hasAccess = scopedIds.some(function(id){ return String(id) === targetId; });
    }
    if (!hasAccess) return res.status(403).json({ error: "Forbidden" });

    var target = await User.findById(targetId).lean();
    if (!target) return res.status(404).json({ error: "Agent not found" });

    // Effective qTarget — sum subordinate targets for manager/TL, else own.
    // For agent-set expansion below, also pre-resolve direct sales reports so
    // qDeals / qLeads / qCalls / qRev aggregate across the team subtree
    // (matches the FE KPIsPage TL/manager view at App.js L18833-L18837).
    var oid = new mongoose.Types.ObjectId(targetId);
    var qTarget = 0;
    var agentOids = [oid];
    if (target.role === "manager" || target.role === "team_leader") {
      var team = await User.find({ active: { $ne: false }, role: { $in: ["sales", "team_leader"] }, reportsTo: target._id }).select("_id qTargets role").lean();
      qTarget = team.reduce(function(s,u){ return s + (readQTargetServer(u, year, quarter) || 0); }, 0);
      if (!qTarget) qTarget = readQTargetServer(target, year, quarter) || 0;
      team.forEach(function(u){ agentOids.push(u._id); });
    } else {
      qTarget = readQTargetServer(target, year, quarter) || 0;
    }

    // Lead/deal aggregation. agentId or splitAgent2Id matches any agent in
    // the resolved team subtree (sales role = just self). archived excluded.
    var ownerMatch = { archived: { $ne: true }, $or: [{ agentId: { $in: agentOids } }, { splitAgent2Id: { $in: agentOids } }] };

    var qLeadsCount = await Lead.countDocuments(Object.assign({}, ownerMatch, {
      createdAt: { $gte: qStart, $lt: qEnd },
      source:    { $ne: "Daily Request" }
    }));

    var dealRows = await Lead.aggregate([
      { $match: {
        archived: { $ne: true },
        $and: [
          { $or: [{ agentId: { $in: agentOids } }, { splitAgent2Id: { $in: agentOids } }] },
          { $or: [{ status: "DoneDeal" }, { globalStatus: "donedeal" }] }
        ]
      }},
      { $addFields: {
        // dealDate is stored as a string ("YYYY-MM-DD"); convert; fall back
        // through eoiDate → updatedAt → createdAt to mirror getDealDate.
        _effDate: {
          $let: {
            vars: { d1: { $convert: { input: "$dealDate", to: "date", onError: null, onNull: null } } },
            in:   { $ifNull: ["$$d1", { $ifNull: [
              { $convert: { input: "$eoiDate", to: "date", onError: null, onNull: null } },
              { $ifNull: ["$updatedAt", "$createdAt"] }
            ]}]}
          }
        }
      }},
      { $match: { _effDate: { $gte: qStart, $lt: qEnd } }},
      { $project: { budget: 1, projectWeight: 1, project: 1, agentId: 1, splitAgent2Id: 1 } }
    ]);

    // Apply weight × split locally to mirror the FE math at
    // App.js KPIsPage L18951 (parseBudget × getProjectWeight × splitMultiplier).
    // Weight resolution chain:
    //   1) Lead.projectWeight when set AND != 1 (the denormalised cache that
    //      server.js cascades on the project-weight PUT handler).
    //   2) AppSetting.projectWeights[project] fallback for the edge case where
    //      a row pre-dates the cascade or was created without the project
    //      name in the cache.
    //   3) Default 1.
    // splitMult mirrors splitMultiplier(d, visibleUserIds) at App.js L9648:
    //   no split        → 1
    //   both sides in agentOids → 1 (each card adds 50%, sum = 100% — for the
    //                                visible scope, the full deal counts once)
    //   only one side in agentOids → 0.5
    var pwDoc = await AppSetting.findOne({ key: "projectWeights" }).lean();
    var pwMap = (pwDoc && pwDoc.value && typeof pwDoc.value === "object") ? pwDoc.value : {};
    var agentOidSet = new Set(agentOids.map(function(o){ return String(o); }));
    var qDeals = dealRows.length;
    var qRev = 0;
    for (var i = 0; i < dealRows.length; i++) {
      var d = dealRows[i];
      var w;
      if (typeof d.projectWeight === "number" && d.projectWeight !== 1) w = d.projectWeight;
      else if (d.project && pwMap[d.project] != null) w = Number(pwMap[d.project]) || 1;
      else w = 1;
      var bg = parseDealTotalFromBudget(d.budget);
      var hasSplit = !!d.splitAgent2Id;
      var splitMult = 1;
      if (hasSplit) {
        var pri = String(d.agentId && d.agentId._id ? d.agentId._id : d.agentId || "");
        var sec = String(d.splitAgent2Id && d.splitAgent2Id._id ? d.splitAgent2Id._id : d.splitAgent2Id || "");
        splitMult = (agentOidSet.has(pri) && agentOidSet.has(sec)) ? 1 : 0.5;
      }
      qRev += bg * w * splitMult;
    }

    // Calls: count across the same agent set so TL/manager view aggregates
    // the team's calls (matches FE KPIsPage which scans myActs by team uid).
    var qCalls = await Activity.countDocuments({
      userId: { $in: agentOids },
      type:   "call",
      createdAt: { $gte: qStart, $lt: qEnd }
    });

    var qProg = qTarget > 0 ? Math.min(100, Math.round((qRev / qTarget) * 100)) : 0;

    res.json({
      uid:     targetId,
      name:    target.name || "",
      role:    target.role || "",
      year:    year,
      quarter: quarter,
      qTarget: qTarget,
      qLeads:  qLeadsCount,
      qDeals:  qDeals,
      qCalls:  qCalls,
      qRev:    qRev,
      qProg:   qProg
    });
  } catch (e) {
    console.error("[GET /api/agents/:id/quarterly-stats]", e && e.message);
    res.status(500).json({ error: e && e.message ? e.message : "quarterly_stats_failed" });
  }
});

// STEP 3 — single-DR detail endpoint. Mirrors the role visibility of the
// list handler so the FE can refetch a full DR (including eoiDocuments[])
// after ?fields=summary has stripped them from the list response. Today
// the DR side panel doesn't render heavy fields, so no FE caller is wired
// to this yet — it ships available-for-future-use alongside the list
// strip so the strip is reversible without an asymmetric API surface.
app.get("/api/daily-requests/:id", auth, async function(req, res) {
  try {
    if (!mongoose.Types.ObjectId.isValid(req.params.id)) return res.status(400).json({ error: "Invalid id" });
    var r = await DailyRequest.findById(req.params.id).populate("agentId", "name title").lean();
    if (!r) return res.status(404).json({ error: "Not found" });
    var role = req.user.role;
    var aid = r.agentId && r.agentId._id ? String(r.agentId._id) : String(r.agentId || "");
    if (role === "sales") {
      if (aid !== String(req.user.id)) return res.status(404).json({ error: "Not found" });
    } else if (role === "team_leader" || role === "manager" || role === "director") {
      var scoped = new Set((await getScopedUserIds(req.user) || []).map(function(id){ return String(id); }));
      if (!scoped.has(aid)) return res.status(403).json({ error: "Forbidden" });
    }
    res.json(r);
  } catch(e) { res.status(500).json({ error: e.message }); }
});

app.put("/api/daily-requests/:id", auth, async function(req, res) {
  try {
    // Scope gate (BATCH 2.6 + 2.7): caller must be in an allow-listed role,
    // and either own the DR (sales) or have its current agent inside their
    // reportsTo subtree (TL / manager / director). Admin / sales_admin pass
    // through unrestricted. viewer / hr (and any unknown role) fail closed.
    // 404 vs 403 split: 404 only when the DR truly doesn't exist; 403 when
    // the caller has no permission.
    var callerRoleDr = req.user.role;
    var allowedRolesDrPut = ["admin", "sales_admin", "sales", "team_leader", "manager", "director"];
    if (allowedRolesDrPut.indexOf(callerRoleDr) < 0) {
      return res.status(403).json({ error: "Forbidden — read-only role" });
    }
    if (callerRoleDr === "sales" || callerRoleDr === "team_leader" ||
        callerRoleDr === "manager" || callerRoleDr === "director") {
      var scopeDr = await DailyRequest.findById(req.params.id).select("agentId").lean();
      if (!scopeDr) return res.status(404).json({ error: "Not found" });
      var drAgentIdStr = scopeDr.agentId ? String(scopeDr.agentId) : "";
      if (callerRoleDr === "sales") {
        if (drAgentIdStr !== String(req.user.id)) {
          return res.status(403).json({ error: "Forbidden" });
        }
      } else {
        var scopedDrIds = (await getScopedUserIds(req.user) || []).map(function(id){ return String(id); });
        if (!drAgentIdStr || scopedDrIds.indexOf(drAgentIdStr) < 0) {
          return res.status(403).json({ error: "Forbidden" });
        }
      }
    }
    // Admin-only gate: "Deal Cancelled" can only be set by admin users.
    if (req.body.status === "Deal Cancelled" && req.user.role !== "admin" && req.user.role !== "sales_admin") {
      return res.status(403).json({ error: "Only admin can set Deal Cancelled status" });
    }
    // Normalize agentId — on edit the frontend can send a populated
    // {_id, name, ...} object from a prior populate(), which would CastError.
    req.body.agentId = normId(req.body.agentId);
    var update = Object.assign({}, req.body, { lastActivityTime: new Date() });
    // Never overwrite agentId with null/empty — only update if explicitly provided and valid
    if (!update.agentId) delete update.agentId;
    // Permanent meeting marker — stamp once, never overwrite. Strip any
    // client-supplied value first so only this server logic can set it.
    delete update.hadMeeting;
    delete update.meetingDoneAt;
    // Capture previous status on EOI / DoneDeal transition so cancels can restore it.
    // Also used to decide whether this is the FIRST transition into MeetingDone.
    var prevDr = null;
    if (req.body.status === "EOI" || req.body.status === "DoneDeal" || req.body.status === "MeetingDone") {
      prevDr = await DailyRequest.findById(req.params.id).lean();
    }
    // CallbackBell auto-clear (2026-05-18 rebuild) — DR variant of the same
    // hygiene applied in PUT /api/leads/:id. When this PUT logs new
    // status/feedback activity AND there's a stale callbackTime in the past,
    // clear it so the bell drops the row immediately. Skipped when the
    // caller is rescheduling.
    if (req.body.callbackTime === undefined &&
        (req.body.status || req.body.notes !== undefined || req.body.lastFeedback !== undefined)) {
      var preDr = prevDr || await DailyRequest.findById(req.params.id).select("callbackTime").lean();
      if (preDr && preDr.callbackTime) {
        var drOldCb = new Date(preDr.callbackTime);
        if (!isNaN(drOldCb.getTime()) && Date.now() > drOldCb.getTime()) {
          update.callbackTime = "";
        }
      }
    }
    if ((req.body.status === "EOI" || req.body.status === "DoneDeal") && prevDr && prevDr.status && prevDr.status !== req.body.status) {
      if (req.body.status === "EOI") { update.preEoiStatus = prevDr.status; update.eoiStatus = "Pending"; }
      else { update.preDealStatus = prevDr.status; update.dealStatus = ""; }
    }
    if (req.body.status === "MeetingDone" && prevDr && !prevDr.hadMeeting) {
      update.hadMeeting = true;
      update.meetingDoneAt = new Date();
    }
    var r = await DailyRequest.findByIdAndUpdate(req.params.id, update, { new: true }).populate("agentId", "name title");
    if (req.body.status) {
      var actNote = "DailyReq: " + req.body.status;
      if (req.body.notes) actNote += " | " + req.body.notes;
      // Snapshot client identity so dashboard DR-activity rows can resolve
      // the client (populate("leadId") misses DR ids — we'd otherwise lose
      // both the name and the _id needed for click-through).
      await Activity.create({ userId: req.user.id, type: "status_change", note: actNote, leadId: r._id, clientName: r.name || "", clientPhone: r.phone || "" });
      // If status is DoneDeal or EOI — create/update a Lead mirror in the main collection
      if (req.body.status === "DoneDeal" || req.body.status === "EOI") {
        var existingLead = await Lead.findOne({ phone: r.phone, source: "Daily Request" });
        // EOI mirrors need eoiStatus so the EOI page's Pending tab picks
        // them up; DoneDeal mirrors need globalStatus so the Deals page and
        // the admin dashboard both find them.
        var mirrorExtra = {};
        if (req.body.status === "EOI") {
          mirrorExtra.eoiStatus = "Pending"; mirrorExtra.eoiApproved = false;
          // Mirror the PUT-handler globalStatus write (server.js:5777). DR-
          // sourced EOI leads need the flag too so the rotation hard-stops
          // and reports filters that key on globalStatus === "eoi" fire for
          // them just like for EOI leads created via the Leads page.
          mirrorExtra.globalStatus = "eoi";
          // Only stamp eoiDate on the FIRST transition into EOI — preserve the original
          // closure date on every subsequent edit, so the deal-notifications panel doesn't
          // bump old EOIs back to "just now".
          if (!existingLead || !existingLead.eoiDate) {
            // Full ISO (not date-only) so the deal-bell "X hr ago" display
            // measures from the actual transition moment, not UTC midnight.
            mirrorExtra.eoiDate = req.body.eoiDate || new Date().toISOString();
          }
        }
        if (req.body.status === "DoneDeal") {
          mirrorExtra.globalStatus = "donedeal";
          // Only stamp dealDate on the FIRST transition into DoneDeal — preserve the
          // original closure date on every subsequent edit, so old deals don't re-surface
          // as "just closed" in the notifications panel.
          if (!existingLead || !existingLead.dealDate) {
            // Full ISO (not date-only) so the deal-bell "X hr ago" display
            // measures from the actual transition moment, not UTC midnight.
            mirrorExtra.dealDate = new Date().toISOString();
          }
        }
        // GET /api/leads filters sales-role users on assignments.agentId, not
        // the top-level agentId, so a mirror Lead with just agentId is
        // invisible to the very sales user who just created it. Seed an
        // assignments[] entry for the DR's current agent so the mirror is
        // visible in sales' leads list (and therefore on the EOI/Deals page).
        var agentForMirror = r.agentId && r.agentId._id ? r.agentId._id : r.agentId;
        // Phase 2 Slice 4 — resolve the AppSetting weight for the project
        // name we're about to stamp onto the mirror. Both branches (existing
        // lead update + new lead create) use the same resolved value; only
        // the project-name fallback chain differs slightly between branches,
        // so we compute lookup keys per-branch but share the helper.
        var existingProjectFallback = existingLead ? existingLead.project : "";
        var resolvedProjectName = req.body.project || r.propertyType || existingProjectFallback || "";
        var resolvedDrWeight = await resolveDrProjectWeight(resolvedProjectName);
        if (existingLead) {
          var existingMirrorPayload = Object.assign({
            status: req.body.status,
            budget: req.body.budget || r.budget || existingLead.budget,
            project: req.body.project || r.propertyType || existingLead.project,
            unitType: req.body.unitType || r.unitType || existingLead.unitType || "",
            agentId: r.agentId,
            lastActivityTime: new Date(),
            notes: req.body.notes || r.notes || existingLead.notes,
            eoiDeposit: req.body.eoiDeposit || existingLead.eoiDeposit || "",
          }, mirrorExtra);
          if (resolvedDrWeight !== null) existingMirrorPayload.projectWeight = resolvedDrWeight;
          await Lead.findByIdAndUpdate(existingLead._id, existingMirrorPayload);
          // If the existing mirror has no assignment for the current agent,
          // add one so the sales-role leads filter accepts it. Use $addToSet
          // semantics by checking first — $addToSet on sub-docs doesn't dedupe
          // on a single field, so we do the check explicitly.
          if (agentForMirror) {
            var hasAssign = (existingLead.assignments || []).some(function(a) {
              var aid = a && a.agentId && a.agentId._id ? a.agentId._id : (a && a.agentId);
              return String(aid || "") === String(agentForMirror);
            });
            if (!hasAssign) {
              await Lead.findByIdAndUpdate(existingLead._id, {
                $push: { assignments: { agentId: agentForMirror, status: req.body.status, assignedAt: new Date(), lastActionAt: new Date(), rotationTimer: new Date(), statusChangedAt: new Date(), noRotation: false, notes: "", budget: "", callbackTime: "", lastFeedback: "", nextCallAt: null, agentHistory: [] } }
              });
            } else {
              // Sync the agent's assignments status so per-agent views reflect the mirror's new state.
              // statusChangedAt is bumped here even though we can't cheaply read the prior slice
              // status — DR-mirror writes are infrequent and almost always carry a real status
              // change, so the conservative "always bump" approach can't reset the clock spuriously
              // in any realistic flow.
              await Lead.updateOne(
                { _id: existingLead._id, "assignments.agentId": agentForMirror },
                { $set: { "assignments.$.status": req.body.status, "assignments.$.lastActionAt": new Date(), "assignments.$.statusChangedAt": new Date() } }
              );
            }
          }
        } else {
          var seedAssignments = agentForMirror ? [{
            agentId: agentForMirror,
            status: req.body.status,
            assignedAt: new Date(),
            lastActionAt: new Date(),
            rotationTimer: new Date(),
            statusChangedAt: new Date(),
            noRotation: false,
            notes: "",
            budget: "",
            callbackTime: "",
            lastFeedback: "",
            nextCallAt: null,
            agentHistory: []
          }] : [];
          var newMirrorPayload = Object.assign({
            name: r.name, phone: r.phone, phone2: r.phone2 || "",
            email: r.email || "", budget: req.body.budget || r.budget || "",
            project: req.body.project || r.propertyType || "",
            unitType: req.body.unitType || r.unitType || "",
            notes: req.body.notes || r.notes || "",
            status: req.body.status,
            source: "Daily Request",
            agentId: r.agentId,
            callbackTime: r.callbackTime || "",
            lastActivityTime: new Date(),
            eoiDeposit: req.body.eoiDeposit || "",
            assignments: seedAssignments,
          }, mirrorExtra);
          if (resolvedDrWeight !== null) newMirrorPayload.projectWeight = resolvedDrWeight;
          await Lead.create(newMirrorPayload);
        }
        // Real-time broadcast for the Lead mirror. The auto-broadcast
        // middleware only emits dr_updated here (the response path is
        // /api/daily-requests), so admins never received the new/updated
        // mirror Lead until a manual refresh. Emitting lead_updated here
        // — with the full populated doc — matches what a direct Lead PUT
        // would emit, so the frontend lead_updated handler slots the row
        // into p.leads and the EOI / Deals page shows it instantly. The
        // DR's own dr_updated event is still emitted by the middleware
        // after res.json(r), so the DR page also stays live.
        try {
          var mirrorLead = await Lead.findOne({ phone: r.phone, source: "Daily Request" }).populate("agentId", "name title").populate("assignments.agentId", "name title").lean();
          if (mirrorLead) emitLead(mirrorLead);
        } catch(emitErr) { console.error("DR→EOI/Deal mirror broadcast failed (non-fatal):", emitErr.message); }
      } else if (req.body.status === "Deal Cancelled") {
        // DR moved out of EOI/DoneDeal — keep the mirror Lead in sync so the EOI page shows it under Deal Cancelled
        var mirror = await Lead.findOne({ phone: r.phone, source: "Daily Request" });
        if (mirror && (mirror.status === "EOI" || mirror.status === "DoneDeal")) {
          await Lead.findByIdAndUpdate(mirror._id, { status: "Deal Cancelled", eoiApproved: false, lastActivityTime: new Date() });
        }
      }
    }
    // When the EOI/DoneDeal branch ran, surface the mirror Lead id on the
    // response. Lets the DR add-flow upload eoi-documents to the mirror
    // without having to refetch the full /api/leads list to look it up.
    // mirrorLead is var-hoisted; undefined when the branch didn't run.
    if (mirrorLead && mirrorLead._id) {
      var resp = (r && r.toObject) ? r.toObject() : r;
      resp.mirrorLeadId = String(mirrorLead._id);
      return res.json(resp);
    }
    res.json(r);
  } catch(e) { res.status(500).json({ error: e.message }); }
});

app.delete("/api/daily-requests/:id", auth, adminOnly, async function(req, res) {
  try {
    // Read first so we can capture phone for the mirror cascade after delete.
    var drDoc = await DailyRequest.findById(req.params.id).lean();
    await DailyRequest.findByIdAndDelete(req.params.id);
    // Cascade Notification rows pointing at this DR (matches the Lead.delete
    // behaviour at L6010+, Divergence #6 in the audit).
    try { await Notification.deleteMany({ leadId: String(req.params.id) }); } catch(nErr) { console.error("[dr-delete notif cascade]", nErr && nErr.message); }
    try { broadcast("notification_updated", {}); } catch(e) {}
    // Mirror cascade: hard-delete the mirror Lead(s) too. Phone+source
    // guard prevents accidentally deleting an unrelated standalone Lead
    // that shares the phone.
    if (drDoc && drDoc.phone) {
      try {
        var mirrorIds = await Lead.find({ phone: drDoc.phone, source: "Daily Request" }, { _id: 1 }).lean();
        if (mirrorIds.length) {
          var mirrorIdStrs = mirrorIds.map(function(d){ return String(d._id); });
          await Lead.deleteMany({ _id: { $in: mirrorIds.map(function(d){ return d._id; }) } });
          // And the mirror Leads' notifications, mirroring Lead.delete cascade.
          try { await Notification.deleteMany({ leadId: { $in: mirrorIdStrs } }); } catch(nErr2) { console.error("[dr-delete mirror notif cascade]", nErr2 && nErr2.message); }
          try { broadcast("lead_updated", {}); } catch(e) {}
          try { broadcast("notification_updated", {}); } catch(e) {}
        }
      } catch(mErr) { console.error("[dr-delete Lead cascade]", mErr && mErr.message); }
    }
    res.json({ ok: true });
  } catch(e) { res.status(500).json({ error: e.message }); }
});

// ===== ARCHIVE DAILY REQUEST =====
app.put("/api/daily-requests/:id/archive", auth, adminOnly, async function(req, res) {
  try {
    var r = await DailyRequest.findByIdAndUpdate(req.params.id, { archived: true, lastActivityTime: new Date() }, { new: true }).populate("agentId", "name title");
    if (!r) return res.status(404).json({ error: "Daily Request not found" });
    // Mirror cascade: if a mirror Lead exists for this DR (created when the
    // DR transitioned to EOI/DoneDeal — see PUT /api/daily-requests/:id at
    // L8050+), archive it too. Match by phone + source="Daily Request" so
    // standalone non-mirror Leads sharing a phone are unaffected.
    if (r.phone) {
      try {
        var mirrorRes = await Lead.updateMany({ phone: r.phone, source: "Daily Request", archived: { $ne: true } }, { $set: { archived: true } });
        if (mirrorRes && mirrorRes.modifiedCount > 0) {
          // Cascade notifications for any mirror leads we just archived,
          // matching the Lead.archive cascade behaviour. Single deleteMany
          // by phone-resolved leadIds keeps the round-trip count low.
          var mirrorIds = await Lead.find({ phone: r.phone, source: "Daily Request" }, { _id: 1 }).lean();
          var mirrorIdStrs = mirrorIds.map(function(d){ return String(d._id); });
          if (mirrorIdStrs.length) {
            try { await Notification.deleteMany({ leadId: { $in: mirrorIdStrs } }); } catch(nErr) { console.error("[dr-archive notif cascade]", nErr && nErr.message); }
            try { broadcast("notification_updated", {}); } catch(e) {}
          }
          try { broadcast("lead_updated", {}); } catch(e) {}
        }
      } catch(mErr) { console.error("[dr-archive Lead cascade]", mErr && mErr.message); }
    }
    res.json(r);
  } catch(e) { res.status(500).json({ error: e.message }); }
});

app.put("/api/daily-requests/:id/unarchive", auth, adminOnly, async function(req, res) {
  try {
    var r = await DailyRequest.findByIdAndUpdate(req.params.id, { archived: false, lastActivityTime: new Date() }, { new: true }).populate("agentId", "name title");
    if (!r) return res.status(404).json({ error: "Daily Request not found" });
    // Mirror cascade: bring the linked mirror Lead back too.
    if (r.phone) {
      try {
        var mRes = await Lead.updateMany({ phone: r.phone, source: "Daily Request", archived: true }, { $set: { archived: false } });
        if (mRes && mRes.modifiedCount > 0) { try { broadcast("lead_updated", {}); } catch(e) {} }
      } catch(mErr) { console.error("[dr-unarchive Lead cascade]", mErr && mErr.message); }
    }
    res.json(r);
  } catch(e) { res.status(500).json({ error: e.message }); }
});

// ===== DR HISTORY =====
app.get("/api/daily-requests/:id/history", auth, async function(req, res) {
  try {
    var oid = new mongoose.Types.ObjectId(req.params.id);
    var acts = await Activity.find({ leadId: oid })
      .populate("userId", "name")
      .sort({ createdAt: -1 });
    res.json(acts);
  } catch(e) { res.status(500).json({ error: e.message }); }
});

// ===== NOTIFICATIONS =====
// BATCH 3 — Notification rows are stored as shared documents (no recipient
// field on the schema), so per-role visibility is derived at read time:
//   - type=deal/rotation: leadId → Lead.agentId → membership in caller scope
//   - type=attendance_late_5: leadId is overloaded to carry the employee's
//     User._id (see maybeFireLateNotification) → membership in caller scope
// getVisibleNotifications encapsulates that derivation so GET and mark-seen
// share one rule.
async function getVisibleNotifications(req, baseQuery, limit) {
  var role = req.user.role;
  var notifs = await Notification.find(baseQuery).sort({ createdAt: -1 }).limit(limit).lean();
  if (!notifs.length) return notifs;

  var isFullView = (role === "admin" || role === "sales_admin");
  var scopeIdSet = null;
  if (!isFullView) {
    var scopeIdsArr = (await getScopedUserIds(req.user)) || [];
    scopeIdSet = new Set(scopeIdsArr.map(function(id){ return String(id); }));
  }
  var selfId = String(req.user.id);

  // HR with manageAttendance sees all attendance_late_5 (matches the
  // Attendance Team tab read path). HR sees nothing of deal/rotation.
  var hrCanSeeAttendance = false;
  if (role === "hr") {
    try {
      var att = await getAttendanceSettings();
      hrCanSeeAttendance = hasAttendancePermission("hr", "manageAttendance", att);
    } catch (e) { hrCanSeeAttendance = false; }
  }

  // Off-site approver capability — anyone with approveOffSiteRequests sees
  // pending rows. Owner is true unconditionally; sales_admin/hr depend on the
  // settings toggle. Skip the AppSetting lookup entirely when there are no
  // off-site rows in this batch or the role can't approve regardless.
  var canApproveOffSite = false;
  var hasOffsiteRows = notifs.some(function(n){
    return n.type === "offsite_pending" || n.type === "offsite_approved" || n.type === "offsite_rejected";
  });
  if (hasOffsiteRows && (role === "admin" || role === "sales_admin" || role === "hr")) {
    try {
      var attSettings2 = await getAttendanceSettings();
      canApproveOffSite = hasAttendancePermission(role, "approveOffSiteRequests", attSettings2);
    } catch (e) { canApproveOffSite = false; }
  }

  // Build leadId → agentId map for deal/rotation. Same lookup also gives
  // the dead-lead filter (existing behavior — drop notifications whose
  // referenced lead is gone or archived).
  var leadAgentMap = new Map();
  var aliveLeadIds = new Set();
  var dealRotIds = notifs
    .filter(function(n){ return (n.type === "deal" || n.type === "rotation") && n.leadId; })
    .map(function(n){ return n.leadId; });
  if (dealRotIds.length > 0) {
    var objectIds = dealRotIds.map(function(id){
      try { return mongoose.Types.ObjectId.isValid(id) ? new mongoose.Types.ObjectId(id) : null; } catch(e){ return null; }
    }).filter(Boolean);
    if (objectIds.length > 0) {
      var leadRows = await Lead.find(
        { _id: { $in: objectIds }, archived: { $ne: true } },
        { _id: 1, agentId: 1 }
      ).lean();
      leadRows.forEach(function(l){
        var lid = String(l._id);
        aliveLeadIds.add(lid);
        if (l.agentId) leadAgentMap.set(lid, String(l.agentId));
      });
    }
  }

  return notifs.filter(function(n){
    // Drop deal/rotation rows whose lead is gone or archived.
    if ((n.type === "deal" || n.type === "rotation") && n.leadId && !aliveLeadIds.has(String(n.leadId))) {
      return false;
    }

    // Phase R-4: commission_* notifications never appear in the rotation bell.
    // They surface only via the in-page banner on the Commissions page through
    // a dedicated endpoint (GET /api/notifications/commission below).
    if (n.type && n.type.indexOf("commission_") === 0) return false;

    // Off-site notifications — visibility split: pending rows go to approvers,
    // approved/rejected rows go to the requester. These rules apply to every
    // role (including admin/sales_admin) so the bell stays clean for users
    // who can't act on a given row.
    if (n.type === "offsite_pending") {
      return canApproveOffSite;
    }
    if (n.type === "offsite_approved" || n.type === "offsite_rejected") {
      return String(n.leadId || "") === selfId;
    }

    if (isFullView) return true;

    if (n.type === "attendance_late_5") {
      if (role === "viewer") return false;
      if (role === "hr") return hrCanSeeAttendance;
      var leId = String(n.leadId || "");
      if (!leId) return false;
      if (role === "sales") return leId === selfId;
      // director / manager / team_leader → employee userId must be in subtree
      return !!(scopeIdSet && scopeIdSet.has(leId));
    }

    if (n.type === "deal" || n.type === "rotation") {
      if (role === "viewer" || role === "hr") return false;
      var lid = String(n.leadId || "");
      if (!lid) return false; // legacy entries with no leadId are dropped for non-full view
      var aid = leadAgentMap.get(lid);
      if (!aid) return false;
      if (role === "sales") return aid === selfId;
      return !!(scopeIdSet && scopeIdSet.has(aid));
    }

    // Unknown type — drop for non-full view.
    return false;
  });
}

app.post("/api/notifications", auth, async function(req, res) {
  try {
    // BATCH 3 — type whitelist + per-call authorization. Without this gate
    // any authenticated user can forge a notification with any leadId, which
    // would defeat the GET-side scoping by seeding bogus rows.
    var role = req.user.role;
    var body = req.body || {};
    var type = body.type;

    if (type !== "deal" && type !== "rotation") {
      // attendance_late_5 is server-managed (see maybeFireLateNotification)
      // and must never be fired from a client. Other types are unrecognized.
      return res.status(403).json({ error: "Invalid notification type" });
    }

    if (role !== "admin" && role !== "sales_admin") {
      var leadId = body.leadId;
      if (!leadId || !mongoose.Types.ObjectId.isValid(leadId)) {
        return res.status(403).json({ error: "Invalid leadId" });
      }
      var oid = new mongoose.Types.ObjectId(leadId);
      var callerId = String(req.user.id);
      var allowed = false;

      if (type === "deal") {
        // Caller must be the agent on the referenced Lead OR DailyRequest.
        // DR-funnel deal notifications post the DR._id as leadId before the
        // Lead mirror is in place — see App.js addDealNotif call sites in the
        // DR status-change and EOI-submission flows.
        var lead = await Lead.findById(oid, { agentId: 1 }).lean();
        if (lead && lead.agentId && String(lead.agentId) === callerId) {
          allowed = true;
        }
        if (!allowed) {
          var dr = await DailyRequest.findById(oid, { agentId: 1 }).lean();
          if (dr && dr.agentId && String(dr.agentId) === callerId) {
            allowed = true;
          }
        }
      } else { // rotation
        // Auto-rotate is client-triggered by the FROM agent after the lead's
        // agentId has already flipped to the new owner, so current-agent-only
        // would block legitimate sales-fired rotation notifications. Allow
        // any past or present owner.
        var leadR = await Lead.findById(oid, { agentId: 1, previousAgentIds: 1 }).lean();
        if (leadR) {
          if (leadR.agentId && String(leadR.agentId) === callerId) allowed = true;
          if (!allowed && Array.isArray(leadR.previousAgentIds)) {
            allowed = leadR.previousAgentIds.some(function(p){ return String(p) === callerId; });
          }
        }
      }

      if (!allowed) {
        return res.status(403).json({ error: "Not allowed to fire notification for this lead" });
      }
    }

    // 2026-05-18 — populate eventTime (the underlying event's real time, not
    // the row's insert time). FE may pass body.eventTime explicitly (preferred
    // — it's accurate to the moment of action); if absent, look up the lead and
    // copy from dealDate/eoiDate. Final fallback: now. Without this, dropdown
    // rows render "1 day ago" for every notification since createdAt clusters
    // around the load time on backfilled rows (see commit 945aa84 regression).
    if (!body.eventTime && body.type === "deal" && body.leadId && mongoose.Types.ObjectId.isValid(body.leadId)) {
      try {
        var evLead = await Lead.findById(body.leadId).select("dealDate eoiDate createdAt").lean();
        if (evLead) {
          var raw = (body.status === "DoneDeal" ? evLead.dealDate : evLead.eoiDate) || evLead.dealDate || evLead.eoiDate || evLead.createdAt;
          if (raw) body.eventTime = raw;
        }
      } catch(evErr) { /* non-fatal — fall through to default */ }
    }
    if (!body.eventTime) body.eventTime = new Date();
    var n = await Notification.create(body);
    // Notify every connected admin/sales_admin/team_leader so their deal-bell
    // unread badge increments in real time without waiting for the next bell
    // open or page reload. Every other Notification.create site already
    // broadcasts (rotation at 9108/9225, offsite at 5395, commission at
    // 2710/18305) — this brings the client-fired create into line.
    try { broadcast("notification_updated", {}); } catch(e) {}
    // Submission confirmation: push the submitting agent that their deal/EOI
    // is pending. type "deal" covers both (status distinguishes). Fire-and-forget.
    if (body.type === "deal" && (body.status === "DoneDeal" || body.status === "EOI")) {
      var isDoneDeal = body.status === "DoneDeal";
      var ln = body.leadName || "a lead";
      sendPushNotification(
        [String(req.user.id)],
        isDoneDeal ? "Deal submitted" : "EOI submitted",
        isDoneDeal ? ("Your deal on " + ln + " is pending approval")
                   : ("Your EOI on " + ln + " is pending approval"),
        { type: "deal_submit", status: String(body.status), leadId: String(body.leadId || "") }
      ).catch(function(){});
    }
    res.json(n);
  } catch(e) { res.status(500).json({ error: e.message }); }
});

app.get("/api/notifications", auth, async function(req, res) {
  try {
    var uid = req.user.id;
    var type = req.query.type || null;
    var query = {};
    var requestedTypes = [];
    if (type) {
      // Allow ?type=a,b,c to fetch multiple types in one round-trip. Used by
      // the off-site bell which lumps pending/approved/rejected together.
      if (String(type).indexOf(",") !== -1) {
        requestedTypes = String(type).split(",").map(function(s){ return s.trim(); }).filter(Boolean);
        query.type = { $in: requestedTypes };
      } else {
        requestedTypes = [type];
        query.type = type;
      }
    }
    // Default cap depends on requested types. deal/rotation-only requests
    // drop to 200 — the bell only renders the recent handful and the
    // rotation collection has 8000+ rows, so the prior 2000 default was
    // wasteful and slowed initial app load. Mixed-type requests (e.g. the
    // combined deal+rotation+offsite call) must pass an explicit limit;
    // requests with no type at all keep the 2000 default for compatibility.
    var allDealOrRotation = requestedTypes.length > 0 && requestedTypes.every(function(t){
      return t === "deal" || t === "rotation";
    });
    var defaultLimit = allDealOrRotation ? 200 : 2000;
    var limit = Math.min(parseInt(req.query.limit) || defaultLimit, 5000);
    var visible = await getVisibleNotifications(req, query, limit);
    var result = visible.map(function(n) {
      return Object.assign({}, n, { seen: n.seenBy && n.seenBy.indexOf(String(uid)) !== -1 });
    });
    res.json(result);
  } catch(e) { res.status(500).json({ error: e.message }); }
});

app.put("/api/notifications/mark-seen", auth, async function(req, res) {
  try {
    var uid = String(req.user.id);
    var type = req.body.type || null;
    // BATCH 3 — caller may only mark-seen rows they are permitted to see.
    // Reuse the same scope as GET; constrain updateMany to visible _ids.
    var baseQuery = {};
    if (type) {
      if (String(type).indexOf(",") !== -1) {
        baseQuery.type = { $in: String(type).split(",").map(function(s){ return s.trim(); }).filter(Boolean) };
      } else {
        baseQuery.type = type;
      }
    }
    var visible = await getVisibleNotifications(req, baseQuery, 5000);
    if (!visible.length) return res.json({ ok: true });
    var visibleIds = visible.map(function(n){ return n._id; });
    await Notification.updateMany(
      { _id: { $in: visibleIds }, seenBy: { $ne: uid } },
      { $addToSet: { seenBy: uid } }
    );
    res.json({ ok: true });
  } catch(e) { res.status(500).json({ error: e.message }); }
});

// ===== PHASE R-4 — COMMISSION NOTIFICATIONS =====
// commission_* notifications are filtered out of /api/notifications (the bell
// endpoint) and surfaced only here, on the Commissions page banner. Admin /
// sales_admin only.
app.get("/api/notifications/commission", auth, salesAdminOnly, async function(req, res) {
  try {
    var uid = String(req.user.id);
    var rows = await Notification.find({ type: { $regex: /^commission_/ } })
      .sort({ createdAt: -1 })
      .limit(20)
      .lean();
    var withSeen = rows.map(function(n){
      return Object.assign({}, n, { seen: Array.isArray(n.seenBy) && n.seenBy.indexOf(uid) !== -1 });
    });
    res.json(withSeen);
  } catch(e) {
    console.error("[GET /api/notifications/commission]", e && e.message);
    res.status(500).json({ error: e && e.message ? e.message : "notifications_commission_failed" });
  }
});

// POST /api/notifications/:id/dismiss — per-id dismiss for the commission
// banner. Restricted to commission_* types (other notification streams use
// the bulk mark-seen flow). Adds the caller's user id to seenBy.
app.post("/api/notifications/:id/dismiss", auth, salesAdminOnly, async function(req, res) {
  try {
    if (!mongoose.Types.ObjectId.isValid(req.params.id)) return res.status(400).json({ error: "Invalid id" });
    var n = await Notification.findById(req.params.id);
    if (!n) return res.status(404).json({ error: "Notification not found" });
    if (!n.type || n.type.indexOf("commission_") !== 0) {
      return res.status(400).json({ error: "Dismiss is only supported for commission_* notifications" });
    }
    var uid = String(req.user.id);
    if (!Array.isArray(n.seenBy)) n.seenBy = [];
    if (n.seenBy.indexOf(uid) === -1) {
      n.seenBy.push(uid);
      await n.save();
    }
    res.json({ ok: true });
  } catch(e) {
    console.error("[POST /api/notifications/:id/dismiss]", e && e.message);
    res.status(500).json({ error: e && e.message ? e.message : "notification_dismiss_failed" });
  }
});

// ===== BACKFILL OFF-SITE NOTIFICATIONS =====
// One-shot, idempotent backfill — creates offsite_pending Notification rows
// for any OffSiteRequest still in "pending" state that doesn't already have
// one. Safe to run multiple times. Returns the count actually created.
app.post("/api/admin/backfill-offsite-notifications", auth, adminOnly, async function(req, res) {
  try {
    var pending = await OffSiteRequest.find({ status: "pending" }).populate("userId", "name").lean();
    var created = 0;
    var alreadyExists = 0;
    for (var i = 0; i < pending.length; i++) {
      var r = pending[i];
      var existing = await Notification.findOne({ type: "offsite_pending", fromName: String(r._id) }).lean();
      if (existing) { alreadyExists++; continue; }
      var name = (r.userId && r.userId.name) || "";
      await Notification.create({
        type: "offsite_pending",
        leadId: String(r.userId && r.userId._id ? r.userId._id : r.userId),
        leadName: name,
        agentName: name,
        status: r.type || "",
        reason: r.reason || "",
        fromName: String(r._id),
        createdAt: r.requestedAt || r.createdAt || new Date()
      });
      created++;
    }
    if (created > 0) { try { broadcast("notification_updated", {}); } catch(e){} }
    res.json({ ok: true, totalPending: pending.length, created: created, alreadyExists: alreadyExists });
  } catch (e) {
    console.error("[backfill-offsite-notifications]", e);
    res.status(500).json({ error: e.message });
  }
});

// ===== BULK REASSIGN =====
// ===== FIX MANAGER TEAM IDS =====
// One-time endpoint to auto-assign teamId to managers based on their sales' teamIds
app.post("/api/fix-manager-teams", auth, adminOnly, async function(req, res) {
  try {
    var managers = await User.find({ role: "manager", active: true }).lean();
    var fixed = [];
    for(var i = 0; i < managers.length; i++) {
      var mgr = managers[i];
      if(mgr.teamId) continue; // already has teamId
      // Find a sales user with reportsTo this manager OR that was created under same team
      // Try: find sales whose teamId is set, and this manager has no teamId
      // Strategy: find most common teamId among sales that reportsTo this manager
      var salesUnder = await User.find({ reportsTo: mgr._id }).lean();
      if(salesUnder.length > 0 && salesUnder[0].teamId) {
        var newTeamId = salesUnder[0].teamId;
        await User.findByIdAndUpdate(mgr._id, { teamId: newTeamId, teamName: salesUnder[0].teamName||"" });
        fixed.push({ name: mgr.name, teamId: newTeamId });
      }
    }
    res.json({ ok: true, fixed: fixed });
  } catch(e) { res.status(500).json({ error: e.message }); }
});

// ===== ARCHIVE LEAD =====
app.put("/api/leads/:id/archive", auth, async function(req, res) {
  try {
    // BATCH 2.7 L14 — tightened from adminOnly (manager/TL admitted) to
    // strict admin/sales_admin only. Archiving is destructive-adjacent and
    // must not be available to team-bounded roles cross-team.
    if (req.user.role !== "admin" && req.user.role !== "sales_admin") {
      return res.status(403).json({ error: "Admin only" });
    }
    var lead = await Lead.findByIdAndUpdate(req.params.id, { archived: true }, { new: true });
    // Cascade: cancel any active commission tied to this lead. Archiving was
    // the second user-facing path (after deal-cancel) that should drop a deal
    // from the Commissions page; without this hook, archived deals lingered
    // as active commissions even though their Lead was no longer in the Deals
    // page. Same helper used by /api/leads/:id/deal-cancel.
    try { await cascadeCommissionCancel(req.params.id, "Lead archived by " + (req.user && req.user.name ? req.user.name : "admin"), req.user); } catch(e){ console.error("[commission hook lead-archive]", e && e.message); }
    // Cascade: drop any Notification rows pointing at this lead. The GET-time
    // filter at getVisibleNotifications already drops archived-lead rows for
    // type=deal/rotation, but (a) other types (e.g. legacy "new_lead") slip
    // through that filter, (b) the bell only re-fetches on socket reconnect
    // or page reload so users saw stale rows lingering until next refresh.
    // Eager cleanup + notification_updated emit closes both gaps.
    try { await Notification.deleteMany({ leadId: String(req.params.id) }); } catch(cascadeErr) { console.error("[lead-archive cascade]", cascadeErr && cascadeErr.message); }
    try { broadcast("notification_updated", {}); } catch(e) {}
    // Mirror cascade: if this lead is a DR mirror (source="Daily Request"),
    // archive the originating DR too. Without this the DR keeps showing on
    // the Daily Requests page even though the user archived its mirror from
    // the EOI/Deals page. Phone+source is the established mirror linkage
    // (see PUT /api/daily-requests/:id at L8135). Source guard prevents a
    // standalone non-mirror Lead from accidentally archiving an unrelated
    // DR that shares its phone.
    if (lead && lead.source === "Daily Request" && lead.phone) {
      try {
        var drRes = await DailyRequest.updateMany({ phone: lead.phone, archived: { $ne: true } }, { $set: { archived: true, lastActivityTime: new Date() } });
        if (drRes && drRes.modifiedCount > 0) { try { broadcast("dr_updated", {}); } catch(e) {} }
      } catch(drErr) { console.error("[lead-archive DR cascade]", drErr && drErr.message); }
    }
    res.json(lead);
  } catch(e) { res.status(500).json({ error: e.message }); }
});

// ===== UNARCHIVE LEAD =====
// Dedicated endpoint mirrors the DR side (PUT /api/daily-requests/:id/unarchive)
// and lets us cascade archived:false to the linked DR mirror in one place.
// ArchivePage previously used the generic PUT /api/leads/:id with {archived:false}
// which had no cascade — restored leads stayed paired with archived DRs.
app.put("/api/leads/:id/unarchive", auth, async function(req, res) {
  try {
    if (req.user.role !== "admin" && req.user.role !== "sales_admin") {
      return res.status(403).json({ error: "Admin only" });
    }
    var lead = await Lead.findByIdAndUpdate(req.params.id, { archived: false }, { new: true });
    if (!lead) return res.status(404).json({ error: "Lead not found" });
    // Mirror cascade: bring the linked DR back too if this lead is a DR mirror.
    if (lead.source === "Daily Request" && lead.phone) {
      try {
        var drRes = await DailyRequest.updateMany({ phone: lead.phone, archived: true }, { $set: { archived: false, lastActivityTime: new Date() } });
        if (drRes && drRes.modifiedCount > 0) { try { broadcast("dr_updated", {}); } catch(e) {} }
      } catch(drErr) { console.error("[lead-unarchive DR cascade]", drErr && drErr.message); }
    }
    res.json(lead);
  } catch(e) { res.status(500).json({ error: e.message }); }
});

// ===== FACEBOOK WEBHOOK =====
app.get("/api/fb-webhook", function(req, res) {
  var mode = req.query["hub.mode"];
  var token = req.query["hub.verify_token"];
  var challenge = req.query["hub.challenge"];
  if (mode === "subscribe" && token === process.env.FB_VERIFY_TOKEN) {
    res.status(200).send(challenge);
  } else {
    res.status(403).json({ error: "Forbidden" });
  }
});

app.post("/api/fb-webhook", async function(req, res) {
  try {
    var body = req.body;
    if (body.object === "page") {
      for (var entry of body.entry) {
        for (var change of (entry.changes || [])) {
          if (change.field === "leadgen") {
            var leadgenId = change.value.leadgen_id;
            var fbRes = await fetch("https://graph.facebook.com/v19.0/" + leadgenId + "?fields=field_data&access_token=" + process.env.FB_PAGE_TOKEN);
            var fbData = await fbRes.json();
            if (fbData.field_data) {
              var leadData = {};
              fbData.field_data.forEach(function(field) {
                var val = field.values && field.values[0] ? field.values[0] : "";
                var key = field.name.toLowerCase();
                if (key.includes("name")) leadData.name = val;
                else if (key.includes("phone") || key.includes("mobile")) leadData.phone = val;
                else if (key.includes("email")) leadData.email = val;
              });
              if (leadData.name || leadData.phone) {
                // Skip if phone is missing or if this phone is already in the CRM.
                var fbPhone = String(leadData.phone || "").trim();
                if (!fbPhone) {
                  console.log("FB lead skipped: no phone");
                } else {
                  var existing = await findLeadByPhone(fbPhone);
                  if (existing) {
                    console.log("FB lead skipped — duplicate phone:", fbPhone);
                  } else {
                    // Manual Assignment Window: if enabled, route FB leads to
                    // the unassigned queue instead of immediate auto-pick.
                    var fbSettings = null;
                    try { fbSettings = await getRotationSettings(); } catch(e) {}
                    var fbWindowMins = fbSettings ? Number(fbSettings.manualAssignmentWindowMinutes || 0) : 0;
                    var agentId = null;
                    if (fbWindowMins <= 0) {
                      // Rotation-eligible roles: sales, team_leader, manager. NEVER sales_admin.
                      var agents = await User.find({ role: { $in: ["sales","team_leader","manager"] }, active: true });
                      if (agents.length > 0) {
                        var counts = await Promise.all(agents.map(function(a) { return Lead.countDocuments({ agentId: a._id }); }));
                        agentId = agents[counts.indexOf(Math.min(...counts))]._id;
                      }
                    }
                    var newLead = await Lead.create({
                      name: leadData.name || "Facebook Lead",
                      phone: fbPhone,
                      email: leadData.email || "",
                      // Pass the literal through normalizeSource for pattern
                      // consistency with the inbound + manual paths. Returns
                      // "Facebook" unchanged since it's already canonical.
                      source: normalizeSource("Facebook"),
                      status: "Potential",
                      agentId: agentId,
                      lastActivityTime: new Date(),
                      notes: "Facebook Lead Ads",
                      assignments: agentId ? [{ agentId: agentId, status: "NewLead", assignedAt: new Date(), lastActionAt: new Date(), rotationTimer: new Date(), statusChangedAt: new Date(), noRotation: false, notes: "", budget: "", callbackTime: "", lastFeedback: "", nextCallAt: null, agentHistory: [] }] : [],
                      manualWindowExpiresAt: (fbWindowMins > 0 && !agentId) ? new Date(Date.now() + fbWindowMins*60000) : null
                    });
                    if (agentId) {
                      await Activity.create({ userId: agentId, leadId: newLead._id, type: "note", note: "Facebook Lead Ads" });
                    }
                    console.log("FB lead saved:", newLead.name, fbWindowMins > 0 && !agentId ? "(queued)" : "");
                  }
                }
              }
            }
          }
        }
      }
    }
    res.status(200).json({ status: "ok" });
  } catch(e) {
    console.error("FB Webhook error:", e.message);
    res.status(200).json({ status: "ok" });
  }
});

